			m_hThread[THREAD_VISION_DETECT] = m_pThread[THREAD_VISION_DETECT]->m_hThread;
			GetExitCodeThread(m_hThread[THREAD_VISION_DETECT],&ExitCode[THREAD_VISION_DETECT]);
