	int nAutoKey = 0;
	FAS_GetIoBit(2,TRUE,AUTO_MODE,&nAutoKey);
	if(nAutoKey != TRUE)
	{
		AfxMessageBox("Change Key (Manual -> Auto)!!"); 
		Sleep(1000);
		return;
	}
#endif
