void CP8CA_LcDispView::OnClickCmdDataEditor()   
{
	CMainFrame *pFrame = (CMainFrame *)AfxGetMainWnd();
	CP8CA_LcDispView* pView = (CP8CA_LcDispView*)pFrame->GetActiveView();	//ehji 140804
	CP8CA_LcDispDoc *pDoc = GetDocument();

	TCHAR ApplicationPath[_MAX_PATH];

	SetOffLine(TRUE);// by ckh 2009.03.20 
	// 모드 설정=>running (Onine status -> offline)	
	m_pDevice->MNET_BitSet(DISP_BIT, false);

	int count=0;
	char pathbuffer[_MAX_PATH];
	char searchfile[] = "D:\\TOP\\P8CA_LC\\P8CA_LC_EXE\\P8CA_DataEditor.exe";
	char envvar[] = "PATH";
	_searchenv( searchfile, envvar, pathbuffer );
	if( *pathbuffer != '\0' ){
		while( pathbuffer[count] !='\0' ){
			count++;
		}
		for( int z=0; z<count-20; z++ ){
			ApplicationPath[z]=pathbuffer[z]; // Application 디렉토리를 저장한다.
		}
		ApplicationPath[z]='\0'; // 문자열 마지막에 꼭있어야할 문자.
	}
	else 
	{
		AfxMessageBox("P8CA_DataEditor.exe 를 찾을 수 없습니다.");
		// 모드 설정=>running (Onine status -> online)	
		m_pDevice->MNET_BitSet(DISP_BIT, true);
		SetOffLine(FALSE);// by ckh 2009.03.20 
		return;
	}

	STARTUPINFO si; 
	::ZeroMemory( &si, sizeof(si)); 
	si.cb = sizeof( si);
	PROCESS_INFORMATION pi; 
	CString strFilePath;
	strFilePath.Format("%s\\%s",ApplicationPath,"P8CA_DataEditor.exe");

	// 자식 프로세스를 시작한다.. 
	if( !::CreateProcess( _T(strFilePath), _T("P8CA_DataEditor.exe"), NULL, NULL, FALSE, 0, NULL, NULL, &si, &pi)) 
	{ 
		AfxMessageBox("!외부프로그램 수행 오류\n"); 
		// 모드 설정=>running (Onine status -> online)	
		m_pDevice->MNET_BitSet(DISP_BIT, true);
		SetOffLine(FALSE);// by ckh 2009.03.20 
		return;
	} 
	::WaitForSingleObject( pi.hProcess, INFINITE); // 자식이 끝날때 까지 기다리기 
	::DeleteObject( pi.hProcess );// 핸들을 더 이상 사용하지 않음을 알린다.  
	::DeleteObject( pi.hThread ); // 핸들을 더 이상 사용하지 않음을 알린다. 
	// 모드 설정=>running (Onine status -> online)	
	m_pDevice->MNET_BitSet(DISP_BIT, true);
	SetOffLine(FALSE);// by ckh 2009.03.20 
	pDoc->ReadRecipeFile(pDoc->m_structOperatorModeRecipeData.strFrontRecipeName);
	if(pDoc->m_structDataEditor.m_bUse_Vision)
	{
		pView->SendMessage(WM_VISION_INIT,NULL,NULL);	//ehji 140804
		pDoc->Read_Vision_Y_Offset(); //CELL FOR VISION 전 Y OFFSET READ
		pDoc->Read_Vision_X_Offset();	//ehji 141025
 		pDoc->Make_Cell_for_Vision();
 		pDoc->Make_Recipe_for_Vision();
	}
}

void CP8CA_LcDispView::OnClickCmdFileMng() 
{
	CP8CA_LcDispDoc *pDoc =	(CP8CA_LcDispDoc*) GetDocument(); 
	CFileMng dlg;
	dlg.DoModal();
	// 기존 m_arRecipeData 데이타를 모두 삭제한다..
	pDoc->m_arRecipeData.RemoveAll();

	// File Management에서 변경된 내용이 있으므로, Recipe 셋팅을 다시한다.
	pDoc->FindRecipeData();
	pDoc->ReadRecipeFile(pDoc->m_structOperatorModeRecipeData.strFrontRecipeName);

	// 현재 Open된 Recipe의 이름이 변경될 수 있으므로, 이름설정을 다시한다.
	// 현재 Open된 Recipe가 File Manage에서 지워져서는 안된다.
	SubDisplayRecipeName();
}

