		nSubPanelCnt=0;
		nMaxCountSub =	(CIM_Information.Panal_Max_Num - CIM_Information.SubPanalNo_Start + 1)/16 + 1;//16개 Panel 기준 Count //20220225 JEONGYONG - Log 간소화
		if(nMaxCountSub > 18) nMaxCountSub = 18;
