{
	CMainFrame *pFrame = (CMainFrame*)AfxGetMainWnd();
	CP8CA_LcDispDoc *pDoc = (CP8CA_LcDispDoc*)pFrame->GetActiveDocument();

	CString str="",strTemp = "";
	int n=0;

	str.Format("%4x",atoi(m_strMachineNo));
	m_pDevice->MNET_WriteWord(BaseAddr_DISP+0x31,str,1);

	// 배출처리관련..
	str.Empty(); strTemp.Empty();
	str = CIM_Information.Glass_add_data1;

	n = m_pDevice->HexConvert(str.GetAt(0))*4096 + 
		m_pDevice->HexConvert(str.GetAt(1))*256 + 
		m_pDevice->HexConvert(str.GetAt(2))*16 + 
		m_pDevice->HexConvert(str.GetAt(3));

	switch(atoi(m_strMachineNo))
	{
		case 1 : // A 호기
			n |= 0x0400; break;   //11번째 0000 0100 0000 0000
		case 2 : // B 호기
			n |= 0x0800; break;   //12번째 
		default:
			n |= 0x0000; break;
	}
	str.Format("%4x", n);
	str += CIM_Information.Glass_add_data23;  // 2 words
	
	str += CIM_Information.Glass_history1;
	str += CIM_Information.Glass_history2;
	m_pDevice->MNET_WriteWord(BaseAddr_DISP+0x2B, str, 5);		// 실처리 보고 Data 영역

	// 실처리 되는 Glass data : Pair Glass 
	m_pDevice->MNET_WriteWord(BaseAddr_DISP+0x10,CIM_Information.GlassDataPair,16);
	// 실처리 되는 Glass data 자Glass
	str.Empty();
	str = CIM_Information.Recipe_Number;
	str += CIM_Information.Glass_Type;
	str += CIM_Information.Lot_number;
	str += m_pDevice->MakeHexDatatoPLC(CIM_Information.Glass_ID, 14);  // 7 word
	str += CIM_Information.Glass_Judge_Code12;
	m_pDevice->MNET_WriteWord(BaseAddr_DISP+0x20, str, 11);

}

