void CP8CA_LcDispView::Write_Information3()	//실처리 보고 3
{
	CMainFrame *pFrame = (CMainFrame*)AfxGetMainWnd();
	CP8CA_LcDispDoc *pDoc = (CP8CA_LcDispDoc*)pFrame->GetActiveDocument();
	int i;
	int AddCount = 0;
	CString strSum,str;
	DWORD WriteAdd;
	Rms_Report_add = 0x0000;
	//Recipe Number,level,type,status,unitnumber
	strSum.Empty();
	CString strLog;
	SaveRMSLog("<RMS>Recipe List");
	for(i=0;i<MAX_RECIPE;i++)
	{
		if(pDoc->m_bRecipeExist[i])
		{
			str.Empty();
			str.Format("%04x",i+1);//Recipe Number
			SaveRMSLog(str);
			strLog.Format("%03d",i+1);
			SaveRMSLog(strLog);
			strSum +=str;
//2010.09.28 by tskim Level, type 수정
			strSum += "0002";//level
			strSum += m_pDevice->MakeHexDatatoPLC("M",2);//type
			strSum += "303030303030";//ver
			strSum += "0002";
			str.Format("%04x",atoi(pDoc->m_strMachineNo));
			SaveRMSLog(pDoc->m_strMachineNo);
			strSum += str; //pDoc->m_strMachineNo;
			AddCount +=8;
		}
	}
	m_pDevice->MNET_WriteWord(CIM_DISP_RMS+Rms_Report_add+0x10,strSum,AddCount);
}

