	//TF측 배출위치 간섭없음on , TF측 배출동작중 off인지?, 배출연결 가능 on (Disp. 입장에서 보면 반입시)
	if(ThreadStage.OffLineMode==FALSE)
	{
		nTFStatus = m_pLcView->m_pDevice->MNET_ReadBit_As_Word(BaseAddr_TF+BitTFSendIF);
		if((nTFStatus & 0x0010) != 0)           // 배출 연결 가능한 상태에서
		{
			if((nTFStatus & 0x0005) != 0x0001)  // 배출동작에 간섭이 있거나 배출 동작 중에 있으면 Error.
			{
				m_pLcView->SendMessage(WM_ERROR,200,NULL);
				ThreadStage.ExitFlag = TRUE;
				return;
			}
		}
 		//TF측 수취위치 간섭없음on , TF측 수취동작중 off인지?, 배출연결 가능 on
		nTFStatus = m_pLcView->m_pDevice->MNET_ReadBit_As_Word(BaseAddr_TF+BitTFReceiveIF);
		if((nTFStatus & 0x0010) != 0) // 배출연결가능 on
		{
			if((nTFStatus & 0x0005) != 0x0001)
			{
				m_pLcView->SendMessage(WM_ERROR,200,NULL);
				ThreadStage.ExitFlag = TRUE;
				return;
			}
		}
	}
