					m_pLcView->m_pDevice->MNET_BitSet(DISP_SEND+SEND_ENABLE, true);		
					
					//Sleep(1); // by ckh 2009.03.09 막음.
					//# Glass Data 출력 on
					m_pLcView->m_pDevice->MNET_BitSet(DISP_SEND+GLASS_DATA_OUT, true);					
					
					if(ThreadStage.bGlassBothways==FALSE)	// 단일 배출
					{
						strLog.Format("단일 동작 반출 Step %3d : Glass배출 처리 => 배출 연결 가능/Glass Data 출력 on ", JobStepBK);
						m_pLcView->SaveLog(1, strLog);
						JobStepBK++;					
					}
					else	 // 동시 취출 : ThreadStage.bGlassBothways==TRUE
					{												
						m_pLcView->WriteTasData(TAS_EXCHANGE, 2, BIT_ON); //수취 연결 가능 ON
						//# 수취측 Normal Status ON (수취연결가능 on)
						m_pLcView->m_pDevice->MNET_BitSet(DISP_RECEIVE+RECEIVE_ENABLE, true);
						
						//# Glass Data요구 ON은 원래 위치에서 살리자.
						//m_pLcView->m_pDevice->MNET_BitSet(DISP_RECEIVE+GLASS_DATA_REQ, true); 
						
						m_pLcView->WriteTasData(TAS_EXCHANGE, 8, BIT_OFF); //수취 요구 OFF
						//# Load Request OFF (수취요구 OFF)
						m_pLcView->m_pDevice->MNET_BitSet(DISP_RECEIVE+RECEIVE_REQUEST, false);
						
						m_pLcView->WriteTasData(TAS_EXCHANGE, 9, BIT_OFF); //수취 간섭 없음 OFF
						//# Load Enable OFF (수취위치 간섭없음 OFF)
						m_pLcView->m_pDevice->MNET_BitSet(DISP_RECEIVE+OUT_OF_AREA, false);
						strLog.Format("동시 취출 Step %3d : 배출연결가능 on / 수취연결가능 on ", JobStepBK);
						m_pLcView->SaveLog(1, strLog);
						
						JobStepBK++;
					}

					FAS_GetActualPos(AXIS_K1/BOARD_AXES+1,AXIS_K1%BOARD_AXES,&dPos);
					dMoveKdist = dPos;
					

