										m_pLcView->m_bSupHeadInterLock = TRUE;
										g_nSupplyHead = i;
										m_pLcView->g_nSupplyHead_Mem = g_nSupplyHead;
										ThreadStage.strMsg1.Format("중앙 공급 헤드 %d 동일 판넬 사용 헤드 액정 잔량 설정치 초과로 인해 중앙 공급 Skip 함.",i+1);
										m_pLcView->SaveLog(0, ThreadStage.strMsg1);m_pLcView->SaveLog(3, ThreadStage.strMsg1);
