						strLog.Format("동시 취출 Step %3d : 강제 적용 Step TF측 수취완료 on 확인 => 완료수신 on / 배출요구 off / GlassData출력중 off / 실처리 보고", JobStepBK);
						m_pLcView->SaveLog(1, strLog);
