						m_pLcView->WriteTasData(TAS_EXCHANGE, 8, BIT_OFF); //수취 요구 OFF
						//# 수취요구 off
						m_pLcView->m_pDevice->MNET_BitSet(DISP_RECEIVE+RECEIVE_REQUEST, false);		
						
