						//# GLASS DATA READ
						m_pLcView->m_nGlassDataReadStatus = 0;//090527
						m_pLcView->SendMessage(WM_CIMINFO,1,1);  //ReadGlassData(lParam)-> 0: CIM, 1: TRF
						Sleep(10);
						m_pLcView->WriteTasData(TAS_EXCHANGE, 15, BIT_OFF); //Glass Data READ
						//by shin//2009.04.01//장비 상태 보고는 glass data read 후 최신 정보로 업데이트...//
						m_pLcView->SendMessage(WM_CIMINFO,4,1);   //WriteEquipStatus() 0:무, 1:유
						bJobStepCpt = TRUE;
						Sleep(1);
						// Glass Data Display
						m_pLcView->m_pAuto->SendMessage(WM_INFODISP,3,0);

						g_nGlassCount++; 
						g_nTotalGlassCount++; 

