						m_pLcView->WriteTasData(TAS_EXCHANGE, 6, BIT_OFF); //배출 간섭 없음 OFF
						//# 배출위치 간섭없음 off
						m_pLcView->m_pDevice->MNET_BitSet(DISP_SEND+OUT_OF_AREA, false);
