										m_pLcView->m_pDevice->MNET_WriteWord(GLS_SPC_DATA+0x0B,CIM_Information.LotSlot_No_Pair,1);// PAIR=>TFT
										strLog.Format("반입 Step %3d : SELF Glass 종별: CF	요구 Lot:%s	Slot:%s ", JobStepBK,CIM_Information.Pair_Lot,CIM_Information.Pair_Slot);

