											//# Panel Data Request off   
											m_pLcView->m_pDevice->MNET_BitSet(DISP_REPORT+0x18, false);
											strLog.Format("TFT Panel Information 요구 OFF..Time Over");
											bEcsError = TRUE;
	//										m_pLcView->SendMessage(WM_ERROR,300,NULL);	
											tmpStep++;
