										for(i=0;i<MAX_PANEL;i++)	CIM_Information.Panel_NG_Mark[TFT][i] = 1;
	//									m_pLcView->InformationAddDelBk(DATA_TFT,FALSE);// by ckh 2009.02.16 Dot Cancel 데이터를 저장함. 

										m_pLcView->m_pDevice->MNET_BitSet(DISP_REPORT+0x18, false);
