	//											ThreadStage.ExitFlag = true;
											m_strMotionLog[headnum].Format("<M> Head %d P-Axis Pos1 %f Pos2 %f",headnum+1,dPos,dPos1);//2014.12.19 by tskim debug i -> headnum
											m_pLcView->SaveLog(0,m_strMotionLog[headnum]);//2014.12.19 by tskim debug i -> headnum
											m_pLcView->PostMessage(WM_ERROR,145,headnum+1);							
											JobStepBK = 200; // EXIT
