						FAS_SetLocalPara(AXIS_P1/BOARD_AXES+1, (i+AXIS_P1)%BOARD_AXES , 5, AccTime); //P축 Acc Time
						FAS_SetLocalPara(AXIS_P1/BOARD_AXES+1, (i+AXIS_P1)%BOARD_AXES , 6, DecTime); //P축 Dec Time
