								if((ThreadStage.bEmergencyStop == FALSE)&&(ThreadStage.bLimitDetect == FALSE))
								{
									m_pLcView->m_pDevice->StageLineDropNtype(ptLineDropDummy[1][0]+ThreadStage.dAlignOffsetX,ptLineDropDummy[1][1]+ThreadStage.dAlignOffsetY,dTableSpeed,
																		dDischargeSpeedNtype,2);
									for(headnum = 0; headnum < MAX_NOZZLE; headnum++)
									{
										if(m_pLcDoc->m_structPatternData[pattern_num].m_bIsOnHead[headnum] == TRUE)
										{
											if(Drop_Info.head_onoff[headnum] == TRUE)
											{
												FAS_GetCommandPos(m_pLcDoc->m_structHeadConfig[headnum].nA[0], m_pLcDoc->m_structHeadConfig[headnum].nA[1], &dPos);
												Sleep(5); //10
												FAS_GetActualPos(m_pLcDoc->m_structHeadConfig[headnum].nA[0], m_pLcDoc->m_structHeadConfig[headnum].nA[1], &dPos1);
												m_strMotionLog[headnum].Format("<M> General Head%d P축(%dLINE DROP완료) CommandPos %f ActualPos %f",headnum+1,nLn,dPos,dPos1);
												m_pLcView->SaveLog(0,m_strMotionLog[headnum]);
											}
										}
									}
								}
								else
								{ 
									FAS_ResetDropQueue(1);
									FAS_ResetSpdQueue(2); //2번 보드에 들어 있는 P축 Clear
									JobStepBK = 200;
									//by shin//2009.04.13//
									ThreadStage.nHomeEnableCount = 0;
									m_pLcView->KillTimer(ID_LIMITDETECT_TIMER);// by ckh 2009.03.09 추가함
									m_pLcView->SendMessage(WM_ERROR,110,NULL);	
									break;
								}	
								/////////////////////////////////////////////////////////
								////// End of 1 Line dropping
								////////////////////////////////////////////////////////
								while(!dwGetIoBit)
								{
									FAS_GetIoBit(1, TRUE, LINE_DORP_COM_IN, &dwGetIoBit);
								}							
								FAS_SetIoBit(1, TRUE, LINE_DORP_COM_OUT, FALSE);
