				m_pLcView->m_nMCNaviStatus[LC_DOTTINGCHK] = 1;
				m_pLcView->McNaviStatusReport();
				if ( g_bJobMovePos ) bSMoveJobPos = false; 
				if(ThreadStage.bEmergencyStop == TRUE) JobStepBK = 200;
				else JobStepBK = 34;
				break;
