							double SMarkPos[MAX_NOZZLE] = {0.0,};
							for(int i=0;i<MAX_NOZZLE;i++)
							{
								if(i<MAX_NOZZLE/2)
								{
									SMarkPos[i] = m_pLcDoc->m_structDataEditor.m_dMarkX[0]-m_pLcDoc->m_dTeachData[15][0] + (HEAD_DIST*i);
								}
								else
								{
									SMarkPos[i] = m_pLcDoc->m_structDataEditor.m_dMarkX[1]-m_pLcDoc->m_dTeachData[15][1] - (HEAD_DIST*((MAX_NOZZLE-1)-i));
								}
							}
							bPosResult1 = m_pLcView->m_pDevice->HeadSPosition_Check(SMarkPos[0],SMarkPos[1],SMarkPos[2],SMarkPos[3],SMarkPos[4],SMarkPos[5],SMarkPos[6],
														SMarkPos[7],SMarkPos[8],SMarkPos[9],SMarkPos[10],SMarkPos[11],SMarkPos[12],SMarkPos[13], 
														SMarkPos[14],SMarkPos[15],FALSE);
