										m_pLcView->SaveDB_HistoryLog(atoi(m_pLcView->pN_Func->m_structNParam[iheadindex].m_strModuleID),iheadindex,DB_RUN,NULL,"N-DUMMY DROP END");

									m_pLcDoc->m_dOffset[0][iheadindex] -= ((drop_num*m_pLcDoc->m_structAdjustCondition.dTargetWeight[0])/1000);
//									m_pLcDoc->m_dOffset[0][iheadindex] -= (((Drop_Info.m_dBasePos[iheadindex]-Drop_Info.m_dFullBasePos[iheadindex])/BASE_PULSE)/1000);//여기 수정 필요...
									
									m_pLcDoc->m_Cunsumption_Data[6] += ((drop_num*m_pLcDoc->m_structAdjustCondition.dTargetWeight[0])/1000); //20160227 Consumption YSM Dummy Drop

