												m_structParam.nDuty        = m_pLcDoc->m_structPatternData[m_pLcDoc->m_nMMGpatStatus[iheadindex]].m_dNDuty[iheadindex]; //duty
												m_structParam.nFrequecy    = (int)m_pLcDoc->m_structPatternData[m_pLcDoc->m_nMMGpatStatus[iheadindex]].m_dNHz; //hz
