// 			FAS_GetFreeContLinearQueue(1, &m_pLcView->wFreeContLinearQueue_Test);
// 			FAS_GetFreeCircleQueue(1, &m_pLcView->wFreeCircleQueue_Test);
// 			FAS_GetFreeAxisQueue(1, AXIS_S_MASTER, &m_pLcView->wFreeAxisQueue_Test1);
// 			FAS_GetFreeAxisQueue(1, AXIS_K_MASTER, &m_pLcView->wFreeAxisQueue_Test2);
// 			m_pLcView->strLog_Test.Format("\tCur_Y\t%.3f\tVel\t%.3f\t(%d)_(%d)_(%d)_(%d)_(%d)_(%d)_(%d)_(%d)",m_pLcView->dDropCurPos_Y_Test,m_pLcView->dDropVel_Test,(int)m_pLcView->wDropQueue_Test
// 				,(int)m_pLcView->wFreeArcQueue_Test,(int)m_pLcView->wFreeArcMotionQueue_Test,(int)m_pLcView->wFreeLinearQueue_Test,(int)m_pLcView->wFreeContLinearQueue_Test,(int)m_pLcView->wFreeCircleQueue_Test,(int)m_pLcView->wFreeAxisQueue_Test1,(int)m_pLcView->wFreeAxisQueue_Test2);
