UINT ThreadVisionDetectFunc(LPVOID pParam)
{
	THREADPARAMS *pThreadParams = (THREADPARAMS *)pParam;
	CP8CA_LcDispView *m_pLcView = pThreadParams->pLcView;
	CP8CA_LcDispDoc *m_pLcDoc = pThreadParams->pLcDoc;
	delete pThreadParams;

	UINT JobStepBK = 0; 

	CString strLog = "" , strTempGlassID = "";

	int nTempNumber = 0 , nBlank = 0 , nRet = 0 , nCount = 0, i = 0; 

	double dCommandPos = 0.0; 

	WORD wTempDropCountIO = 0, wIODropCountResult1 = 0; 
	WORD wTempDropCountResult = 0 , wDropCountResult = 0; 

//	CASE 0  ~ 19  : COMMUNICATION INITIAL , CHECK 
//	CASE 10 ~ 15  : DATA SETTING & MOTION 
//  CASE 100	  : RESULT 
	while(!ThreadVisionDetect.ExitFlag)
	{
		if      ( ThreadVisionDetect.bWritingFlag     == TRUE ) ThreadVisionDetect.JobStep = JobStepBK = 0; 
		else if ( ThreadVisionDetect.bLineDropping    == TRUE ) ThreadVisionDetect.JobStep = JobStepBK = 11; 
		else if ( ThreadVisionDetect.bResultCheckFlag == TRUE ) ThreadVisionDetect.JobStep = JobStepBK = 100;
		else													ThreadVisionDetect.JobStep = JobStepBK ;

		switch(ThreadVisionDetect.JobStep)
		{
		case 0:
			ThreadVisionDetect.bWritingFinish = FALSE; 
			strLog.Format("<AUTO>Vision Drop Count Start, JobStepBK = %d", JobStepBK);
			_NVision.Save_Vision_Log(strLog);

			ThreadVisionDetect.strMsg1.Format("%s Step %d",strLog,JobStepBK);

			ThreadVisionDetect.bWritingFlag = FALSE; 

//			BACK → FRONT CASE 밖에 없음. 
			_NVision.m_structScan_Info.m_bDir_TTB = TRUE;
//150717 SCAN START POS 이상관련 
// SCAN INFO WRITE 전 값 갱신 한다. 
			if ( _NVision.m_structScan_Info.m_bDir_TTB )
				_NVision.m_structScan_Info.m_dStartPos = m_pLcDoc->m_dTeachData[26][1]; 
			else
				_NVision.m_structScan_Info.m_dStartPos = m_pLcDoc->m_dTeachData[26][0]; 
			JobStepBK++; 
			break; 
		case 1:
			if(_NVision.m_structVision_Status.m_bComm_Ok)
			{
				_NVision.m_structVision_Status.m_nError_Code 
									= m_pLcView->Send_Msg_2_Vision(_SEND_NOT_FILE_PATH);

				if( _NVision.m_structVision_Status.m_nError_Code != _VISION_ERR_NOTHING )
				{
					JobStepBK = 200;
					ThreadVisionDetect.bErrorFlag = TRUE; 
					ThreadVisionDetect.nErrorCode = 402; 
					break;
				}
//////////////////////////////////////////////////////////////////jykim 161219 PART SCAN 180K
 				if(!m_pLcDoc->m_structN_Vision.m_bPartScanMode)
 					_NVision.m_structVision_Status.m_nError_Code 
 									= m_pLcView->Write_2_Vision(_CSV_CELL_INFO);
 				else
					_NVision.m_structVision_Status.m_nError_Code 
									= m_pLcView->Write_2_Vision(_CSV_CELL_INFO_N_GANTRY);
//////////////////////////////////////////////////////////////////

				if(_NVision.m_structVision_Status.m_nError_Code == _VISION_ERR_NOTHING)
				{
					_NVision.m_structVision_Status.m_nError_Code 
									= m_pLcView->Write_2_Vision(_CSV_RECIPE_INFO);
//160903 DUAL INTENSITY //160929 JYKIM
					 if(_NVision.m_structVision_Status.m_nError_Code == _VISION_ERR_NOTHING)
					{
						 if( m_pLcDoc->m_structDataEditor.m_bDualIntensity )
						 {
							_NVision.m_structVision_Status.m_nError_Code 
										= m_pLcView->Write_2_Vision(_CSV_THRESHOLD_INFO);

							 if(_NVision.m_structVision_Status.m_nError_Code != _VISION_ERR_NOTHING)
							{
								JobStepBK = 200;
								ThreadVisionDetect.bErrorFlag = TRUE; 
								ThreadVisionDetect.nErrorCode = 402; 

								break;
							}
						 }
					}
					else
					{
						JobStepBK = 200;
						ThreadVisionDetect.bErrorFlag = TRUE; 
						ThreadVisionDetect.nErrorCode = 402; 

						break;
					}
				}
				 if(_NVision.m_structVision_Status.m_nError_Code != _VISION_ERR_NOTHING)
				{
					JobStepBK = 200;
					ThreadVisionDetect.bErrorFlag = TRUE; 
					ThreadVisionDetect.nErrorCode = 402; 

					break;
				}
			}
			else
			{
				AfxMessageBox("communication error");
				JobStepBK = 200;
				ThreadVisionDetect.bErrorFlag = TRUE; 
				ThreadVisionDetect.nErrorCode = 401; 
				break;
			}
//	TRRIGER OPERATION ON
			Sleep(100);				FAS_SetIoBit(4, TRUE, TRG_OPER_SIG, TRUE); 	

			ThreadVisionDetect.bWritingFinish = TRUE; 
			JobStepBK++; 
			break;
//		CASE 2 JOBSTEPBK 대기 로 사용. 
		case 2:	
			break; 
		case 3:
			break; 
		case 4:
			break; 
		case 5:
			break; 
		case 6:
			break; 
		case 7:
			break; 
		case 8:
			break; 
		case 9:
			break; 
		case 10:	
			break;
		case 11:
			ThreadVisionDetect.bPrepareBeforeLineDrop = FALSE; 

			strLog.Format("<AUTO>VISION DATA WRITING..", JobStepBK);
			_NVision.Save_Vision_Log(strLog);

			ThreadStage.strMsg1.Format("%s Step %d",strLog,JobStepBK);

#if LINE1
			Sleep(100);				FAS_SetIoBit(4, TRUE, VISION_LAMP1, TRUE);  //ehji
			Sleep(100);				FAS_SetIoBit(4, TRUE, VISION_LAMP2, TRUE);  //ehji
#else
//	VISION LAMP IO ON
			Sleep(100);				FAS_SetIoBit(4, TRUE, VISION_LAMP1, TRUE);  
			Sleep(100);				FAS_SetIoBit(4, TRUE, VISION_LAMP2, TRUE);  
// 	TRRIGER ENC & TRG RESET IO ON 
// 			Sleep(100);				FAS_SetIoBit(4, TRUE, TRG_ENC_RST, TRUE);  
// 			Sleep(100);				FAS_SetIoBit(4, TRUE, TRG_TRG_RST, TRUE);  
// 	TRRIGER ENC & TRG RESET IO OFF
// 			Sleep(100);				FAS_SetIoBit(4, TRUE, TRG_ENC_RST, FALSE);  
// 			Sleep(100);				FAS_SetIoBit(4, TRUE, TRG_TRG_RST, FALSE);  
#endif
/////////////////////////////////////////////////////////////////////////jykim 161219 PART SCAN 180K
//161214 VISION PART SCAN
			if(g_nLn<=1) 
				ThreadVisionDetect.nLineDropStatus=PART_SCAN_START;

			else if(g_nLn>=g_nTotalLinecount-1) 
				ThreadVisionDetect.nLineDropStatus=PART_SCAN_FINISH;

			else 
				ThreadVisionDetect.nLineDropStatus=PART_SCAN_MOTIONNING;

			if(m_pLcDoc->m_structN_Vision.m_bPartScanMode)
			{
				if      ( ThreadVisionDetect.nLineDropStatus == PART_SCAN_START )
				{
					_NVision.m_structScan_Info.m_nPartScanmode = 3; 
				}
				else if ( ThreadVisionDetect.nLineDropStatus == PART_SCAN_MOTIONNING )
				{
					_NVision.m_structScan_Info.m_nPartScanmode = 4; 
				}
				else
				{
					_NVision.m_structScan_Info.m_nPartScanmode = 5; 
				}
			}
			else
				_NVision.m_structScan_Info.m_nPartScanmode = 0; 

						_NVision.m_structScan_Info.m_nPartScanCount	= m_pLcDoc->m_structN_Vision.m_nPartScanLineCount; 
/////////////////////////////////////////////////////////////////////////jykim 161219 PART SCAN 180K
			if (   m_pLcDoc->m_structPatternData[0].m_nDroppingStartPos == 0 
				|| m_pLcDoc->m_structPatternData[0].m_nDroppingStartPos == 1  )
			{
				_NVision.m_structScan_Info.m_bScanDirection = FALSE; // LEFT
			}
			else
			{
				_NVision.m_structScan_Info.m_bScanDirection = TRUE; // RIGHT
			}

/////////////////////////////////////////////////////////////////////////jykim 161219 PART SCAN 180K

			//Write Scan Info...
			if(m_pLcView->Write_2_Vision(_CSV_SCAN_INFO) != _VISION_ERR_NOTHING)
			{
				JobStepBK = 200;
				ThreadVisionDetect.bErrorFlag = TRUE; 

				ThreadVisionDetect.nErrorCode = 402; 
			}
			if(JobStepBK == 200) break;

			ThreadVisionDetect.bPrepareBeforeLineDrop = TRUE; 

			ThreadVisionDetect.bLineDropping = FALSE; 
			JobStepBK++; 
			break; 
		case 12:
			//GLASS ID 가공 
			strTempGlassID = CIM_Information.GlassID_ASC; 
//			strTempGlassID = "AUTO_SCANNING"; 

			nBlank         = strTempGlassID.FindOneOf(" ");
			strTempGlassID = strTempGlassID.Mid(0, nBlank);

			if(_NVision.SendMsg_to_Vision(_SEND_REQ_START_INSP, strTempGlassID, &nRet).Compare(strTempGlassID) != 0)
			{
				JobStepBK = 200;
				ThreadVisionDetect.bErrorFlag = TRUE; 

				ThreadVisionDetect.nErrorCode = 410; 
			}
			else if(nRet == RES_ERR_TIMEOVER)
			{
				JobStepBK = 200;
				ThreadVisionDetect.bErrorFlag = TRUE; 

				ThreadVisionDetect.nErrorCode = 411; 
			}
			else if(nRet == RES_ERR_DISMATCH)
			{
				JobStepBK = 200;
				ThreadVisionDetect.bErrorFlag = TRUE; 

				ThreadVisionDetect.nErrorCode = 412; 
			}
			else if(nRet < 0)
			{
				JobStepBK = 200;
				ThreadVisionDetect.bErrorFlag = TRUE;
				
				ThreadVisionDetect.nErrorCode = 402; 
			}
			if(JobStepBK == 200) break;

			JobStepBK++; 
			break; 
		case 13:
			JobStepBK++; 
			break; 
		case 14:
			JobStepBK++; 
			break; 
		case 15:
			JobStepBK++; 
			break; 
		case 16:
			JobStepBK++;	
			break; 
		case 17:
			JobStepBK++;	
			break; 
		case 18:
			if ( ThreadVisionDetect.bLineDroppingFinish ) JobStepBK++; 
			Sleep(100);
			break;
		case 19:
			if(_NVision.SendMsg_to_Vision(_SEND_NOT_STOP, "NORMAL", &nRet).Compare("OK") != 0)
			{
				JobStepBK = 200;
				ThreadVisionDetect.bErrorFlag = TRUE; 
			}
			if(JobStepBK == 200) break;

			JobStepBK++; 
			break; 
		case 20:
			JobStepBK = 200; 			
			break; 			
		case 200:

			strLog.Format("VISION SCAN END", JobStepBK);
			_NVision.Save_Vision_Log(strLog);

			ThreadVisionDetect.ExitFlag = TRUE; 
			break; 			
		}
		Sleep(10); 
	}
	return 0;	
}


