LONG CP8CA_LcDispView::OnMeasuredDataSave( WPARAM wParam, LPARAM lParam ) 
{
	CP8CA_LcDispDoc *pDoc =	(CP8CA_LcDispDoc*) GetDocument(); 
	int i=0;
	double dPos=0.0;

	//  wParam: Head Index ( 0~ 15) lParam: 측정(except 0)/Balance R&R(0)	 // 새로운 값을 맨 위로 밀어 내기..
	for(i = 499; i > 0 ; i--)
	{
		pDoc->m_dMeasuredData[wParam][i] = pDoc->m_dMeasuredData[wParam][i-1];
		pDoc->m_dMeasuredData_Target[wParam][i] = pDoc->m_dMeasuredData_Target[wParam][i-1];
		pDoc->m_dMeasuredData_Total[wParam][i] = pDoc->m_dMeasuredData_Total[wParam][i-1];
	}

	if(ThreadStage.JobFlag == STAGE_AUTO && g_nLoopCount[wParam] == 2)
	{
		for(i = 499; i > 0 ; i--)
		{
			pDoc->m_dMeasuredData_First[wParam][i] = pDoc->m_dMeasuredData_First[wParam][i-1];
		}
	}

	if(lParam == 0) // Balance R&R
	{
		if(wParam >= 0 && wParam < 2)
			pDoc->m_dMeasuredData[wParam][0] = (float)(ThBal[BALID1].dSecondData);
		else if(wParam >= 2 && wParam < 4)
			pDoc->m_dMeasuredData[wParam][0] = (float)(ThBal[BALID2].dSecondData);
		else if(wParam >= 4 && wParam < 6)
			pDoc->m_dMeasuredData[wParam][0] = (float)(ThBal[BALID3].dSecondData);
		else if(wParam >= 6 && wParam < 8)
			pDoc->m_dMeasuredData[wParam][0] = (float)(ThBal[BALID4].dSecondData);
		else if(wParam >= 8 && wParam < 10)
			pDoc->m_dMeasuredData[wParam][0] = (float)(ThBal[BALID5].dSecondData);
		else if(wParam >= 10 && wParam < 12)
			pDoc->m_dMeasuredData[wParam][0] = (float)(ThBal[BALID6].dSecondData);
		else if(wParam >= 12 && wParam < 14)
			pDoc->m_dMeasuredData[wParam][0] = (float)(ThBal[BALID7].dSecondData);
		else if(wParam >= 14 && wParam < 16)
			pDoc->m_dMeasuredData[wParam][0] = (float)(ThBal[BALID8].dSecondData);

		if(g_bMultiTargetMeas)
			pDoc->m_dMeasuredData_Target[wParam][0] = pDoc->m_structAdjustCondition.dMultiTarget[wParam][Drop_Info.nMeasurePerDrop[wParam]];
		else
			pDoc->m_dMeasuredData_Target[wParam][0] = pDoc->m_structAdjustCondition.dTargetWeight[wParam];
	}
	else
	{	//가장 상위 Index(0)를 갖는 Data로 써준다..// m_dMeasuredData[] : 단위 mg으로 미리 환산시켜져 있다.
		if(wParam >= 0 && wParam < 2)
		{
			pDoc->m_dMeasuredData[wParam][0] = (float)((ThBal[BALID1].dSecondData-ThBal[BALID1].dRecentData)/(pDoc->m_structAdjustCondition.nDropCount[wParam]*pDoc->m_structAdjustCondition.nMeasureCycle));
			pDoc->m_dMeasuredData_Total[wParam][0] = (float)(ThBal[BALID1].dSecondData-ThBal[BALID1].dRecentData);
		}
		else if(wParam >= 2 && wParam < 4)
		{
			pDoc->m_dMeasuredData[wParam][0] = (float)((ThBal[BALID2].dSecondData-ThBal[BALID2].dRecentData)/(pDoc->m_structAdjustCondition.nDropCount[wParam]*pDoc->m_structAdjustCondition.nMeasureCycle));
			pDoc->m_dMeasuredData_Total[wParam][0] = (float)(ThBal[BALID2].dSecondData-ThBal[BALID2].dRecentData);
		}
		else if(wParam >= 4 && wParam < 6)
		{
			pDoc->m_dMeasuredData[wParam][0] = (float)((ThBal[BALID3].dSecondData-ThBal[BALID3].dRecentData)/(pDoc->m_structAdjustCondition.nDropCount[wParam]*pDoc->m_structAdjustCondition.nMeasureCycle));
			pDoc->m_dMeasuredData_Total[wParam][0] = (float)(ThBal[BALID3].dSecondData-ThBal[BALID3].dRecentData);
		}
		else if(wParam >= 6 && wParam < 8)
		{
			pDoc->m_dMeasuredData[wParam][0] = (float)((ThBal[BALID4].dSecondData-ThBal[BALID4].dRecentData)/(pDoc->m_structAdjustCondition.nDropCount[wParam]*pDoc->m_structAdjustCondition.nMeasureCycle));
			pDoc->m_dMeasuredData_Total[wParam][0] = (float)(ThBal[BALID4].dSecondData-ThBal[BALID4].dRecentData);	
		}
		else if(wParam >= 8 && wParam < 10)
		{
			pDoc->m_dMeasuredData[wParam][0] = (float)((ThBal[BALID5].dSecondData-ThBal[BALID5].dRecentData)/(pDoc->m_structAdjustCondition.nDropCount[wParam]*pDoc->m_structAdjustCondition.nMeasureCycle));
			pDoc->m_dMeasuredData_Total[wParam][0] = (float)(ThBal[BALID5].dSecondData-ThBal[BALID5].dRecentData);
		}
		else if(wParam >= 10 && wParam < 12)
		{
			pDoc->m_dMeasuredData[wParam][0] = (float)((ThBal[BALID6].dSecondData-ThBal[BALID6].dRecentData)/(pDoc->m_structAdjustCondition.nDropCount[wParam]*pDoc->m_structAdjustCondition.nMeasureCycle));
			pDoc->m_dMeasuredData_Total[wParam][0] = (float)(ThBal[BALID6].dSecondData-ThBal[BALID6].dRecentData);
		}
		else if(wParam >= 12 && wParam < 14)
		{
			pDoc->m_dMeasuredData[wParam][0] = (float)((ThBal[BALID7].dSecondData-ThBal[BALID7].dRecentData)/(pDoc->m_structAdjustCondition.nDropCount[wParam]*pDoc->m_structAdjustCondition.nMeasureCycle));
			pDoc->m_dMeasuredData_Total[wParam][0] = (float)(ThBal[BALID7].dSecondData-ThBal[BALID7].dRecentData);
		}
		else if(wParam >= 14 && wParam < 16)
		{
			pDoc->m_dMeasuredData[wParam][0] = (float)((ThBal[BALID8].dSecondData-ThBal[BALID8].dRecentData)/(pDoc->m_structAdjustCondition.nDropCount[wParam]*pDoc->m_structAdjustCondition.nMeasureCycle));
			pDoc->m_dMeasuredData_Total[wParam][0] = (float)(ThBal[BALID8].dSecondData-ThBal[BALID8].dRecentData);
		}

#if EQ
#else
		double dtemp1,dtemp2;
		BOOL bAdjust = FALSE;
		double nTemp1 = (pDoc->m_structAdjustCondition.dTargetWeight[wParam]*1000);
		for(int nTemp3 = 0; nTemp3<MAX_BAL;nTemp3++)
			bAdjust |= ThBal[nTemp3].bAdjust;
		dtemp1 = (pDoc->m_structAdjustCondition.dTargetWeight[wParam]*1000);
		dtemp2 = dtemp1 * (pDoc->m_structAdjustCondition.dTargetError[wParam]/100);
		if(bAdjust)
			dtemp2 = dtemp1 * (0.15/100);
		while(1)
		{			
			nTemp1 =(double)rand();
			if((dtemp1 - dtemp2)-0.5 < nTemp1 && (dtemp1 + dtemp2)+0.5 > nTemp1) 
				break;
			//nTemp1 =(double)rand(); break;
			//nTemp1 = g_nTotalGlassCount*1000; break;

		}
		
		pDoc->m_dMeasuredData[wParam][0] = (double)(nTemp1/1000);
#endif		

		// Bottle내 LC량
		pDoc->m_dOffset[0][wParam] -= ((pDoc->m_dMeasuredData[wParam][0] * pDoc->m_structAdjustCondition.nDropCount[wParam]* pDoc->m_structAdjustCondition.nMeasureCycle)/1000);

		pDoc->m_Cunsumption_Data[1] += ((pDoc->m_dMeasuredData[wParam][0] * pDoc->m_structAdjustCondition.nDropCount[wParam]* pDoc->m_structAdjustCondition.nMeasureCycle)/1000); //20160227 Consumption YSM Calibration

//#if _VISION
		Drop_Info.m_dMMPerVolume[wParam] = (double)Drop_Info.m_dDistPerDrop[wParam]/pDoc->m_dMeasuredData[wParam][0];
//#endif
		if(g_bMultiTargetMeas)
			pDoc->m_dMeasuredData_Target[wParam][0] = pDoc->m_structAdjustCondition.dMultiTarget[wParam][Drop_Info.nMeasurePerDrop[wParam]];
		else
			pDoc->m_dMeasuredData_Target[wParam][0] = pDoc->m_structAdjustCondition.dTargetWeight[wParam];

//		pDoc->m_nMeasuredRealDropCount[wParam][0] = pDoc->m_lDropCount[wParam];
	}
	if(ThreadStage.JobFlag == STAGE_AUTO && g_nLoopCount[wParam] == 2)
	{
		pDoc->m_dMeasuredData_First[wParam][0] = pDoc->m_dMeasuredData[wParam][0];
	}

	SaveMeasureData(wParam);//data저장.
	pDoc->SaveMeasuredData();

	if(ThreadStage.AdjustInitCode != 'G')
	{
		m_bMesuredDataSaveCompleted = TRUE;
		m_bMesuredDataDisplayEnable = TRUE; // true가 되면 adjust / auto timer에서 data를 표시하고 false로 변환
	}
	return 1L;
}

long CP8CA_LcDispView::OnErrorDisp(WPARAM wParam, LPARAM lParam)
{
	CP8CA_LcDispDoc *pDoc =	(CP8CA_LcDispDoc*) GetDocument(); 

	CTime pTime = CTime::GetCurrentTime();
	CErrMsg dlg; CErrList Member; CErrListAuto Member2; 
	CString strTime,strTemp;

	if(pDoc->m_bAutoManualFlag==TRUE) Member.m_nTempFlag = 1; //090711 각 상황에 따른 Auto / Manual Flag 값 지정 
	else Member.m_nTempFlag = 0 ; 
	
	if(Member.m_bPreviousErrList == TRUE) //090711 이전 로그 보기 Check Box 추가로 조건문 추가 
	{
		strTime.Format("%4d	%4d	",wParam,lParam);
		strTime += CTime::GetCurrentTime().Format("%m	%d	%H	%M	%S	");
		strTemp.Format("%02d/%02d %02d:%02d:%02d" ,pTime.GetMonth(),pTime.GetDay(),pTime.GetHour(),pTime.GetMinute(),pTime.GetSecond());
		FILE *fp;
		fp = fopen("D:\\TOP\\P8CA_LC\\P8CA_LC_EXE\\EList.txt","a");
		fprintf(fp,"%s\n",strTime);
		fclose(fp);
	}
	else //090711 이전 로그 보기 Check Box 추가로 조건문 추가 
	{
		strTime.Format("%4d	%4d	%d\t",wParam,lParam,Member.m_nTempFlag);
		strTime += CTime::GetCurrentTime().Format("%m	%d	%H	%M	%S	");
		strTemp.Format("%02d/%02d %02d:%02d:%02d" ,pTime.GetMonth(),pTime.GetDay(),pTime.GetHour(),pTime.GetMinute(),pTime.GetSecond());
		FILE *fp;
		fp = fopen("D:\\TOP\\P8CA_LC\\P8CA_LC_EXE\\EList_New.txt","a");
		fprintf(fp,"%s\n",strTime);
		fclose(fp);
	}/////////////////////////////////////////////////////////////////////////////
	// Error : Error Code 200번 미만 => 장비 정지,  Alarm : Error Code 200 이상  
	// Alarm : Error Code 200번 미만 => 장비 정지,  Warning : Error Code 200 이상  
	if(wParam <200) dlg.m_nSelectAlarm =0; // Alarm
	else dlg.m_nSelectAlarm =1;			   // Warning

//상한 감지 추가 Head 별 처리
	if(wParam == 151)
	{
		wParam = 7000+lParam;
	}

	if(wParam > 1000) dlg.m_nSelectAlarm = 0;//2010.08.18 by tskim New Define Alarm  Code
//2016.05.10 by tskim
	if(wParam == 409) dlg.m_nSelectAlarm = 0;//2016,05.10 by tskim Vision Drop Count Alarm BM

//	if(wParam == 101) dlg.m_nSelectAlarm = 1;//20211223 JEONGYONG - Door Open Warning 처리
/*	if(wParam == 101) 
	{
		BOOL bMutingON = FALSE;
		FAS_GetIoBit(2,TRUE,MUTING_ON,&bMutingON);
		if(bMutingON == TRUE)
		{
			dlg.m_nSelectAlarm = 1;//Door Open Warning 처리 (0: Alarm, 1: Warning)
		}
		else
		{
			dlg.m_nSelectAlarm = 0;//Door Open Alarm 처리 (0: Alarm, 1: Warning)
		}		
	}
*/
	//2008.01.29 By tskim
	//Alarm 예외 처리...
//	if((wParam <200) && (wParam != 188 || wParam != 33)) dlg.m_nSelectAlarm =0; // Error
//	else if(wParam == 188 || wParam == 33) dlg.m_nSelectAlarm =1;//AutoRun중 Measuring Data Spec` Over
//	else dlg.m_nSelectAlarm =1;	
	//
	dlg.m_nErrCode = wParam;
	dlg.m_nErrCode2 = lParam;
	dlg.DoModal();
	
	for(int i = 0; i < pDoc->m_nCount ; i++)   //090711 Alarm 발생 시 Update 
	{
		Error_Information[i].m_nCode[0] = Error_Information[i+1].m_nCode[0];
		Error_Information[i].m_nCode[1] = Error_Information[i+1].m_nCode[1];
		Error_Information[i].m_nCode[2] = Error_Information[i+1].m_nCode[2];
		Error_Information[i].strTime = Error_Information[i+1].strTime;
	}
	Error_Information[pDoc->m_nCount].m_nCode[0] = wParam;
	Error_Information[pDoc->m_nCount].m_nCode[1] = lParam;
	Error_Information[pDoc->m_nCount].m_nCode[2] = Member.m_nTempFlag;
	Error_Information[pDoc->m_nCount].strTime = strTemp;

/*	if(wParam == 103)
	{
		if(ThreadStage.nHomeEnableCount <3)  // 원점을 다시 잡아야 할 조건인 경우 
		{
			CNormalMsg dlg;
			dlg.m_bOrigin = true;		
			dlg.DoModal();
		}
	}
*/
	m_bSafetyOpened=FALSE;
	return 0L;
}

