void CP8CA_LcDispView::ActQJ71E71TCT_Open()
{
	long lRet = 0;
	//m_actTCP.SetActCpuType(CPU_Q06CPU);
	m_actTCP1.SetActCpuType(CPU_Q06UDHCPU);
	
	// Host : PC
	m_actTCP1.SetActHostAddress("192.168.127.100");
	// PLC
	m_actTCP1.SetActNetworkNumber(10);//11
	m_actTCP1.SetActStationNumber(1);
	// PC 
	m_actTCP1.SetActSourceNetworkNumber(10);//11
	m_actTCP1.SetActSourceStationNumber(2);
	m_actTCP1.SetActTimeOut(100);

//	Sleep(5000);
	lRet = m_actTCP1.Open();
	if( lRet == 0 ) {
		m_pDevice->SetActTCP( &m_actTCP1 );
		g_bActiveTCP = TRUE;
	}
	else{
		g_bActiveTCP = FALSE;
		AfxMessageBox("Ethernet communication fail!");
	}
}

void CP8CA_LcDispView::BalanceModeSet()
{
	CP8CA_LcDispDoc *pDoc = GetDocument();
	CString strPath;
	ifstream fi;

	int nBalMode = 0;
	int nBalLevel = 0;
	char ch[256];

// Balance Mode를 읽어 들인다.
	strPath.Format("%s\\BalanceMode.dat", pDoc->m_strDataPath);
	fi.open(strPath, ios::in);

	if(!fi.is_open())
	{
		AfxMessageBox("BalanceMode.dat파일이 없습니다");
		return;
//
	}
	fi >> nBalMode;
	ThBal[BALID1].nBalanceMode = ThBal[BALID2].nBalanceMode = ThBal[BALID3].nBalanceMode = ThBal[BALID4].nBalanceMode = ThBal[BALID5].nBalanceMode = ThBal[BALID6].nBalanceMode = ThBal[BALID7].nBalanceMode = ThBal[BALID8].nBalanceMode = nBalMode;
	fi >> nBalLevel;
	ThBal[BALID1].nBalanceRifLevel = ThBal[BALID2].nBalanceRifLevel = ThBal[BALID3].nBalanceRifLevel = ThBal[BALID4].nBalanceRifLevel = ThBal[BALID5].nBalanceRifLevel = ThBal[BALID6].nBalanceRifLevel = ThBal[BALID7].nBalanceRifLevel = ThBal[BALID8].nBalanceRifLevel = nBalLevel;
	for(int i=0;i<MAX_BAL;i++)
	{
		fi >> ThBal[i].nBalanceUse;
		ThBal[i].nBalanceUse = 1;
	}
	for(i=0;i<MAX_BAL;i++)
		fi >> ThBal[i].nBalanceType;

	fi.close();	
	
	////////////////// Glass 정보 저장한 File을 Open 하는 붑분도 추가 삽입하였다..^^;
	strPath.Format("%s\\GlassIDSave1.dat", pDoc->m_strDataPath);
	fi.open(strPath, ios::in);

	if(!fi.is_open())
	{
		AfxMessageBox("GlassIDSave1.dat파일이 없습니다");
		return;
	}
	for(i=0;i<10;i++)
	{
		fi >> ch;
		Glass_Inform[TFT_GLASS][i].Glass_ID.Format("%s", ch);
		fi >> ch;
		Glass_Inform[TFT_GLASS][i].Lot_number.Format("%s", ch);
		fi >> ch;
		Glass_Inform[TFT_GLASS][i].Slot_number.Format("%s", ch);
		fi >> ch;
		Glass_Inform[TFT_GLASS][i].Panel_Information.Format("%s", ch);
	}
	fi.close();

	strPath.Format("%s\\GlassIDSave2.dat", pDoc->m_strDataPath);
	fi.open(strPath, ios::in);

	if(!fi.is_open())
	{
		AfxMessageBox("GlassIDSave2.dat파일이 없습니다");
		return;
	}
	for(i=0;i<10;i++)
	{
		fi >> ch;
		Glass_Inform[CF_GLASS][i].Glass_ID.Format("%s", ch);
		fi >> ch;
		Glass_Inform[CF_GLASS][i].Lot_number.Format("%s", ch);
		fi >> ch;
		Glass_Inform[CF_GLASS][i].Slot_number.Format("%s", ch);
		fi >> ch;
		Glass_Inform[CF_GLASS][i].Panel_Information.Format("%s", ch);
	}
	fi.close();

	//////////////////
}


BOOL CP8CA_LcDispView::DoTheJob(int pat, int seq)
{
	CP8CA_LcDispDoc *pDoc =	(CP8CA_LcDispDoc*) GetDocument(); 
	BOOL Do_the_job = false;

	if(seq < pDoc->m_structDataEditor.m_nPatternNum) seq++;
	else { return FALSE; }	
	
	for(pat = 0 ; pat < pDoc->m_structDataEditor.m_nPatternNum ; pat++)
	{
		if(pDoc->m_structPatternData[pat].m_nSequence == seq)
		{
			Do_the_job = true;
			return TRUE;
		}
	}
	return FALSE;
}

