// FTP 서버 연결
void CP8CA_LcDispView::FtpServerConnect()
{
	BOOL bMDSExist = FALSE;
	// 이미 연결된 것이 있으면 해제
	if(m_pConnection!=NULL)
	{
		m_pConnection->Close();		
		delete m_pConnection;
		m_pConnection = NULL;
		Sleep(500);
	}

	// 연결하고자 하는 FTP 서버의 IP 주소, 암호 입력
	CString FtpServer_IP = "192.168.201.29";
	CString FtpDisp_Name = "mds";
	CString FtpPassword = "mds";

	//m_pConnection = m_Session.GetFtpConnection(FtpServer_IP,FtpDisp_Name,FtpPassword);
	try
	{
		m_pConnection = m_Session.GetFtpConnection(FtpServer_IP,FtpDisp_Name,FtpPassword,21,FALSE);
	}
	catch (CInternetException* iex)
	{
		CString str="";
		TCHAR sz[1024];
		iex->GetErrorMessage(sz, 1024);
		iex->ReportError();
		iex->Delete();
		m_Session.Close();
		ThreadStage.ExitFlag = true;
	}

	Sleep(500);
	if(!m_pConnection)
	{
//		delete m_pConnection;
//		m_pConnection = NULL;
		
		if(m_pFileFind)
		{
			delete m_pFileFind;
			m_pFileFind = NULL;
		}

		AfxMessageBox("FTP 연결이 안됩니다.", MB_OK);		
		return;
	}
	// 서버 경로 설정 및 [MDS] 폴더 찾기
	bMDSExist=Ftp_MDS_True();
	if(bMDSExist!=TRUE)	AfxMessageBox("서버에 MDS 폴더가 없습니다.",MB_OK);
}

