CString CP8CA_LcDispView::FtpFileNameFun(CString Lot_Num)
{
	int temp_number=0;
	CString strFtpFileName="", str="";

	strFtpFileName="L";
	for(int i=0;i<2;i++) temp_number += (m_pDevice->HexConvert(Lot_Num.GetAt(i))*(int)pow(16,1-i));
	str.Format("%03d",temp_number);
	strFtpFileName +=str;	

	strFtpFileName +="S";	
	temp_number = 0;
	for(i=0;i<2;i++) temp_number += (m_pDevice->HexConvert(Lot_Num.GetAt(i+2))*(int)pow(16,1-i));
	str.Format("%02d",temp_number);
	strFtpFileName +=str;	

	strFtpFileName +=".txt";	

	return strFtpFileName;
}

BOOL CP8CA_LcDispView::Ftp_FileDownLoad()
{
	BOOL bIoResult =FALSE;
	CString strServerPathName;
	CString strDownLoadpathName;
	CString strSaveFileName;

	CTime t=CTime::GetCurrentTime();

	strSaveFileName.Format("%02d%02d%02d%02d%02d_", t.GetYear()-2000, t.GetMonth(), t.GetDay(), t.GetHour(),t.GetMinute());
	strSaveFileName+=CIM_Information.FtpFileName;
///////////////////
	// FTP 연결을 시도.
	if(ThreadStage.OffLineMode == FALSE)	// Online Mode
	{

		bIoResult=SocketInit();
		if(bIoResult==TRUE)	
		{
			FtpServerConnect();
		}
		else
		{
			m_nAddDelCompleted1=2;
			AfxMessageBox("FTP 통신 소켓이 초기화 되지 않습니다.");
			return FALSE;
		}
		Sleep(500);

///////////////////
		if(m_pConnection)
		{		
			for(int i=0;i<3;i++)
			{	
				strServerPathName="";
				_chdir(_T("D:/MDS"));
				m_pConnection->GetCurrentDirectory(m_strFtpServerDirText);	
				Sleep(500);
				
				strServerPathName = m_strFtpServerDirText +"/"+ CIM_Information.FtpFileName;
				m_pConnection->GetFile(strServerPathName,strSaveFileName);
				Sleep(500);		
			}			
			m_nAddDelCompleted1=1;	// 연결만 되면 1,,,정상적으로 File을 Download 받지 못해도 1 이 된다..
			return TRUE;
		}
		else
		{
			m_nAddDelCompleted1=2;
		}
	}
	m_nAddDelCompleted1=2;	// OFFLINE Mode이거나 연결이 되지 않은 경우
	return FALSE;
}

void CP8CA_LcDispView::FtpFileSort(int nSaveCnt)		// Start 버튼을 누른 경우 한번만 수행한다.
{
	CFileFind filefind;
	//FTP_FILE_INFORM ftpFileInForm[nSaveCnt+1];
	FTP_FILE_INFORM FtpFileInform[1500];
	FTP_FILE_INFORM tmpInform;
	CString str;
	int i=0, j=0;
	int nYear=0, nMonth=0, nDay=0, nHour=0, nMinute=0;

	BOOL bContinue = TRUE;
	int nCount=0;
	if(!(bContinue = filefind.FindFile("D:\\MDS\\*.txt")))
		return;

	while(bContinue)
	{
		if(nCount<1498)
		{
			bContinue = filefind.FindNextFile();
			if(!filefind.IsDirectory())
			{
				FtpFileInform[nCount].sFileName=filefind.GetFileName();
				str.Format(FtpFileInform[nCount].sFileName.Left(10));
				
				nYear = atoi(str.Mid(0, 2));
				nMonth = atoi(str.Mid(2, 2));
				nDay = atoi(str.Mid(4, 2));			
				nHour = atoi(str.Mid(6, 2));			
				nMinute = atoi(str.Mid(8, 2));
				// 초로 환산하여 저장
				FtpFileInform[nCount].lAccessTime = (unsigned long)(nYear*31536000+
																	nMonth*2592000+
																	nDay*86400+
																	nHour*3600+
																	nMinute*60);
				nCount++;
			}
		}
		else	break;
	}

	// Access 시간별로 내림차순 정렬한다.
	if(nCount>nSaveCnt)		
	{
		for(i=0;i<nCount;i++)
		{
			for(j=i;j<nCount;j++)
			{
				if(FtpFileInform[i].lAccessTime<FtpFileInform[j].lAccessTime)
				{
					tmpInform=FtpFileInform[i];
					FtpFileInform[i]=FtpFileInform[j];
					FtpFileInform[j]=tmpInform;
				}
			}
		}
	}
	// 저장해야 할 개수보다 많은 경우 지운다.
	while(nCount>=nSaveCnt)
	{
		::DeleteFile("D:\\MDS\\"+FtpFileInform[nCount].sFileName);
		nCount--;
	}
	
	filefind.Close();
}

