int CP8CA_LcDispView::LevelMaxSearch(int nP, int nH, BOOL bAddORDel)
{
	CP8CA_LcDispDoc *pDoc = GetDocument();

	int n_MaxLevel=0, nDropDataCount = 0, i=0;
	DROP_DATA strDropData;

	nDropDataCount = pDoc->m_structPatternData[nP].m_nDropDataCount;

	for(i = 0; i < nDropDataCount; i++)
	{
		strDropData = pDoc->m_arDropData[nP].GetAt(i);
		if(strDropData.m_nAddDel[nH]!=0)
		{
			if(bAddORDel==TRUE)	// ADD의 최대값을 찾는 경우
			{
				if(strDropData.m_nAddDel[nH]>n_MaxLevel)
					n_MaxLevel=strDropData.m_nAddDel[nH];
			}
			else				// DEL 의 최대값을 찾는 경우 ( (-) 절대값)
			{
				if(strDropData.m_nAddDel[nH]<n_MaxLevel)
					n_MaxLevel=strDropData.m_nAddDel[nH];
			}
		}
	}

	return n_MaxLevel;
}


