CString CP8CA_LcDispView::OnCalDuedate()
{
	CString strTotal = "";
	int temp_Y = 0, temp_M = 0, temp_D = 0, temp_H = 0, temp_B = 0;
	int plus_H = 0,plus_D = 0, plus_M = 0;
	int nMonth = 0;
	if(GetDocument()->m_strSpecTime.GetLength() < 10) GetDocument()->m_strSpecTime = "0000000000";
	if(GetDocument()->m_nSpecTime > 0)
	{
		temp_Y = atoi(GetDocument()->m_strSpecTime.Mid(0,2));
		temp_M = atoi(GetDocument()->m_strSpecTime.Mid(2,2));
		temp_D = atoi(GetDocument()->m_strSpecTime.Mid(4,2));
		temp_H = atoi(GetDocument()->m_strSpecTime.Mid(6,2));
		temp_B = atoi(GetDocument()->m_strSpecTime.Mid(8,2));

		temp_H += GetDocument()->m_nSpecTime;
		plus_D = (int)(temp_H/24);
		if(plus_D > 0)
		{
			temp_H = temp_H%24;
			temp_D += plus_D;
			if(temp_M == 2)
			{
				if(temp_Y % 4 == 0) nMonth = 29;
				else nMonth = 28;
			}
			else if(temp_M == 1 || temp_M == 3 || temp_M == 5 || temp_M == 7 || temp_M == 8 || temp_M == 10 || temp_M == 12) nMonth = 31;
			else nMonth = 30;
			plus_M = (int)(temp_D/nMonth);
			if(plus_M > 0)
			{
				temp_D = temp_D%nMonth;
				temp_M++;
				if(temp_M > 12) 
				{temp_Y++; temp_M = 1;}
			}
		}
	}
	strTotal.Format("%02d%02d%02d%02d%02d",temp_Y,temp_M,temp_D,temp_H,temp_B);
	return strTotal;
}

void CP8CA_LcDispView::SubTimerAutoSpecTime()
{
	CTime pTime = CTime::GetCurrentTime();
	BOOL bAct = FALSE;
	int temp[5] = {0,};

	if(m_strDuedate.GetLength() < 10) m_strDuedate = "0000000000";
	for(int i = 0; i < 10; i+=2)
	{
		temp[i/2] = (int)atoi(m_strDuedate.Mid(i,2));
	}
	if(temp[0] < pTime.GetYear() - 2000) bAct = FALSE;
	else if((temp[1] < pTime.GetMonth()) && (temp[0] == pTime.GetYear() - 2000)) bAct = FALSE;
	else if(temp[2] < pTime.GetDay() && temp[1] == pTime.GetMonth()) bAct = FALSE;
	else if((temp[3] < pTime.GetHour()) && (temp[2] == pTime.GetDay()) && (temp[1] == pTime.GetMonth())) bAct = FALSE;
	else if((temp[4] <= pTime.GetMinute()) && (temp[3] == pTime.GetHour()) && (temp[2] == pTime.GetDay()) && (temp[1] == pTime.GetMonth())) bAct = FALSE;
	else bAct = TRUE;

	if(bAct == FALSE)
	{
		for(i = 0; i < MAX_NOZZLE; i++) GetDocument()->m_nRealSpecCount[i] = 0;
		GetDocument()->m_strSpecTime.Format("%02d%02d%02d%02d%02d",pTime.GetYear() - 2000,pTime.GetMonth(),pTime.GetDay(),pTime.GetHour(),pTime.GetMinute());
		m_strDuedate = OnCalDuedate();		
	}

}

void CP8CA_LcDispView::OnSetData_Error()
{
	CP8CA_LcDispDoc *pDoc = GetDocument();

	int Idx=0,nCode1=0,nCode2=0,m_nMonth,m_nDay,m_nHour,m_nMinite,m_nSecond;
	CString str, strDir;
	int m_nTempFlag=0; 
	//리스트뷰에 있는 모든 항목을 지운다
	int nCode[50][3];
	CString Time[50];
	for(int i = 0; i < 50; i++)
	{
		nCode[i][0] = 0;
		nCode[i][1] = 0;
		nCode[i][2] = 0;  //090711 Auto/Manual 구분을 위하여 추가 
		Time[i] = "";
	}
	FILE *fp;
	
	strDir = "D:\\TOP\\P8CA_LC\\P8CA_LC_EXE\\";
	fp = fopen(strDir+"EList_New.txt","r"); //090711 새로운 EList 형식만 Setting

	if( fp == NULL )
	{
		AfxMessageBox("EList_New.txt 가 존재하지 않으므로 표시할 수 없습니다");
		return;
	}
	while(fscanf(fp,"%d	%d	%d	%d	%d	%d	%d	%d\n",/**/&nCode1,&nCode2,&m_nTempFlag,&m_nMonth,&m_nDay,&m_nHour,&m_nMinite,&m_nSecond) != EOF)
	{
		if(Idx > pDoc->m_nCount )
		{
			for(i = 0; i < pDoc->m_nCount ; i++)
			{
				nCode[i][0] = nCode[i+1][0];
				nCode[i][1] = nCode[i+1][1];
				nCode[i][2] = nCode[i+1][2]; //090711 Auto/Manual 구분을 위하여 추가 
				Time[i] = Time[i+1];
			}
			Idx = pDoc->m_nCount;  
		}
		nCode[Idx][0] = nCode1;
		nCode[Idx][1] = nCode2;
		nCode[Idx][2] = m_nTempFlag;  //090711 Auto/Manual 구분을 위하여 추가 
		Time[Idx].Format("%02d/%02d %02d:%02d:%02d",m_nMonth,m_nDay,m_nHour,m_nMinite,m_nSecond);
		Idx++;
	}
	fclose(fp);
	for( i = 0; i < pDoc->m_nCount+1 ; i++)
	{
		Error_Information[i].m_nCode[0] = nCode[i][0];
		Error_Information[i].m_nCode[1] = nCode[i][1];
		Error_Information[i].m_nCode[2] = nCode[i][2];  //090711 Auto/Manual 구분을 위하여 추가 
		Error_Information[i].strTime = Time[i];
	}
}

