int CP8CA_LcDispView::GateCloseCheck(int headno)
{
#if EQ 
	BOOL bIoResult = FALSE;
	for(int i=0;i<200;i++)
	{
		FAS_GetIoBit(3, false, GATE1_CLOSE_POSITION+headno, &bIoResult);
		
		if(bIoResult == TRUE)
		{
			break;
		}
		Sleep(10);
//		i++;
	}
	if(i>=199) return 100+headno;
	else return headno;
#else 
	return headno;
#endif
	return 100+headno;
}

