void CP8CA_LcDispView::OnClickCmdMotorload() 
{
	// TODO: Add your control notification handler code here
//	return;
	SHELLEXECUTEINFO Process;

	ZeroMemory(&Process, sizeof(SHELLEXECUTEINFO));
	Process.cbSize = sizeof(SHELLEXECUTEINFO) ;		
	Process.fMask = SEE_MASK_NOCLOSEPROCESS;
	Process.hwnd = NULL;
	Process.lpVerb = "open";
	Process.lpFile = "D:\\TOP\\P8CA_LC\\P8CA_LC_EXE\\MotorIF.exe";
	Process.lpParameters = NULL;
	Process.lpDirectory = NULL;
	Process.nShow = SW_SHOWNORMAL;
	Process.hInstApp = NULL;

	
	
	if(g_bMotorLoad_Report == FALSE)
	{
		m_ctrlMotorLoad.SetCaption("Motor Load ON");
		m_ctrlMotorLoad.SetBackColor(YELLOW);
		m_ctrlMotorLoad.SetForeColor(LIGHTRED);
		g_bMotorLoad_Report = TRUE;
		g_nMotorLoadProcess = 1;
		SaveLog(0,"Motor Load ON");

		ShellExecuteEx(&Process);

//		SetTimer(1000,60000,NULL);//Motor Laod Data Timer On		

	}
	else
	{
		m_ctrlMotorLoad.SetCaption("Motor Load OFF");
		m_ctrlMotorLoad.SetBackColor(YELLOW);
		m_ctrlMotorLoad.SetForeColor(BLUE);
		g_bMotorLoad_Report = FALSE;
		g_nMotorLoadProcess = 0;
		SaveLog(0,"Motor Load OFF");

//		KillTimer(1000);//Motor Laod Data Timer

		m_hWndMotorLoad = ::FindWindow(NULL, "MotorIF");
		if(m_hWndMotorLoad == NULL)
		{
			SaveLog(0,"MotorIF.exe Already Shut Down");
			AfxMessageBox("MotorIF.exe Already Shut Down");
		}
		while (m_hWndMotorLoad)
		{
			::PostMessage(m_hWndMotorLoad, WM_CLOSE, 0, 0);
			m_hWndMotorLoad = ::FindWindow("MotorIF", NULL);
		}
	}	
}


void CP8CA_LcDispView::AllRecipeReport(int ntype)
{
	CMainFrame* pFrame = (CMainFrame*)AfxGetMainWnd();
	CP8CA_LcDispDoc* pDoc = (CP8CA_LcDispDoc*)pFrame->GetActiveDocument();

	CString str, temp_str, m_strDataPath;
	int i, nBitCnt;
	DWORD temp_value;
	
	str="";
	for(i=0;i<63;i++) str+="0000";
	m_pDevice->MNET_WriteWord(RECIPE_LIST, str, 63); 

	//#다시 다 읽어와야하네..
	if(ntype!=0)
	{		
		pDoc->FindRecipeData();
	}

	str="";
	temp_value= 0x0000;	 
	//등록된 Recipe 젠체 번호를 할당된 Bit로 보고한다.
	//lbg 081001  0번 Bit는 사용안함.
	//for(i=0; i<1000; i++) //(0~999)
	for(i=1; i<MAX_RECIPE; i++) //(1~999)
	{	
		nBitCnt	= i%16;
		if(pDoc->m_bRecipeExist[i-1])
			temp_value = temp_value | 0x01 << (nBitCnt);		
			
		if(nBitCnt==15||i==999) 
		{
			temp_str.Format("%04x",temp_value);
			str += temp_str;					
			temp_value = 0x0000;//Reset
		}		
	}
//For test 2010.02.18 by tskim 
//	int strlength;
//	strlength = str.GetLength();
	m_pDevice->MNET_WriteWord(RECIPE_LIST, str, 63); 
	//AfxMessageBox(str);

	if(ntype == 1)
	{
		//# Recipe List Change보고..
		m_pDevice->MNET_BitSet(DISP_REPORT+0x0B,TRUE);

		Sleep((int)(pDoc->m_dTeachData[37][0]*1000.0));
		
		m_pDevice->MNET_BitSet(DISP_REPORT+0x0B,FALSE);
	}
}

double CP8CA_LcDispView::GetSuctionDist(int head, double dSuctionWeight)
{
	CP8CA_LcDispDoc* pDoc =	(CP8CA_LcDispDoc*) GetDocument();

	int j=0;
	double dDropSuctionDist=0.0;
	CString strLog;


//	if(pDoc->m_structDataEditor.m_nCalibrationMode == 1)//3Point
	{
		if(dSuctionWeight>=pDoc->m_structCalibData[head].dMeasure[1][0])
		{
			for(j = 0; j <MAX_MEADATA_FORCALIB ; j++)
			{
				dDropSuctionDist += pDoc->m_structCalibData[head].dCoefficient2[j]*pow_simple(dSuctionWeight, (MAX_MEADATA_FORCALIB-j-1));
				strLog.Format("(3Point Get) Head%d dSuctionWeight %.2f dMeasure[1][0] %.2f dDropSuctionDist %.0f",head+1,dSuctionWeight,pDoc->m_structCalibData[head].dMeasure[1][0],dDropSuctionDist);
				SaveBalLog(head/2,strLog);
			}
		}
		else
		{
			for(j = 0; j <MAX_MEADATA_FORCALIB ; j++)
			{
				dDropSuctionDist += pDoc->m_structCalibData[head].dCoefficient1[j]*pow_simple(dSuctionWeight, (MAX_MEADATA_FORCALIB-j-1));
				strLog.Format("(3Point Get) Head%d dSuctionWeight %.2f dDropSuctionDist %.0f",head+1,dSuctionWeight,dDropSuctionDist);
				SaveBalLog(head/2,strLog);
			}
		}
	}
	
	return dDropSuctionDist;
}

void CP8CA_LcDispView::SetMotorAllStop()
{
	int ibd,iaxis;
	// 에러 시에는 항상 모터 정시 상태.
	for(ibd = 1 ; ibd <=3 ; ibd++) 
		for( iaxis = 0 ; iaxis < 16 ; iaxis++) 
			FAS_MoveStop(ibd,iaxis,0); // all axis stop..

	for(iaxis = 0 ; iaxis < 8 ; iaxis++) 
		FAS_MoveStop(4,iaxis,0); // all axis stop..
}

