void CP8CA_LcDispView::OnClickCheckMachine() 
{
	
	// TODO: Add your control notification handler code here
	CMainFrame *pFrame = (CMainFrame*)AfxGetMainWnd();
	CP8CA_LcDispDoc* pDoc = (CP8CA_LcDispDoc*)pFrame->GetActiveDocument();
	short nSel=0x00;

	CMcStatusReport dlg;
	CString str = "" , strTemp;
	dlg.m_nStatusCode = m_nMachineStatus;

	int nResult = dlg.DoModal();
	if(IDOK == nResult)
	{		
		if(dlg.m_nStatusCode ==0)
		{
			nSel=0x03;      //모델 교환
			str = "모델 교환";
		}
		else if(dlg.m_nStatusCode ==1)
		{
			nSel=0x04; //클리닝
			str = "클리링";
		}
		else if(dlg.m_nStatusCode ==2)
		{
			nSel=0x05; //재료 교체
			str = "재료 교체 ";
		}
		else
			return;
		
		// by ckh 2009.02.16
		str +=" 생산준비 상태 설정";
		m_nMachineStatus = dlg.m_nStatusCode; // by ckh 2009.02.16
		m_pDevice->MNET_Mode_Set(m_nMachineStatus +4);

		// by ckh 2009.03.24
		ShowTimer();
	}
	else if(IDCANCEL == nResult )
	{
		if(dlg.m_nStatusCode ==0)
		{
			nSel=0x03;      //모델 교환
			str = "모델 교환";
		}
		else if(dlg.m_nStatusCode ==1)
		{
			nSel=0x04; //클리닝
			str = "클리링";
		}
		else if(dlg.m_nStatusCode ==2)
		{
			nSel=0x05; //재료 교체
			str = "재료 교체 ";
		}
		else
		{
			return;
		}
		str +="생산준비 상태 해제";

		m_nMachineStatus = -1;

		// by ckh 2009.02.16 glass 부분 추가
		if(m_pDevice->Stage_glass_check()==FALSE )	
		{
			m_pDevice->MNET_Mode_Set(1); //IDLE
		}
		else
		{
			m_pDevice->MNET_Mode_Set(0); //RUN
		}
		
		// by ckh 2009.03.24 Time Close
		m_pMCTimer->CloseWindow();
	}
	else
	{
		str = "생산 준비 상태 화면 닫기";
	}
	SaveLog(0,str); // 0: Log, 1: Interface
}

