void CP8CA_LcDispView::LcSupplyInitial1()
{
	//Pinch Valve Close
	FAS_SetIoBit(3, FALSE, PINCH_VALVE_SOL1, FALSE);
	Sleep(200);

	//CDA CLOSE//
	FAS_SetIoBit(3, FALSE, SUPPLY_CDA_SOL1, FALSE);
	Sleep(100); //Sleep 줄이자...//

	//액정 주입구 후진//
	FAS_SetIoBit(3, FALSE, NOZZLE_MOVE_SOL1, FALSE);
	Sleep(0);
}

void CP8CA_LcDispView::LcSupplyInitial2()
{
	//Pinch Valve Close
	FAS_SetIoBit(3, FALSE, PINCH_VALVE_SOL2, FALSE);
	Sleep(200);

	//CDA CLOSE//
	FAS_SetIoBit(3, FALSE, SUPPLY_CDA_SOL2, FALSE);
	Sleep(100);//3000

	//액정 주입구 후진//
	FAS_SetIoBit(3, FALSE, NOZZLE_MOVE_SOL2, FALSE);
	Sleep(0);
}

int CP8CA_LcDispView::LcSupplyStatusCheck1()
{
	BOOL bIoResult = FALSE;
	BOOL bIoResult1 = TRUE;
	BOOL bIoResult11 = TRUE;
	BOOL bIoResult2 = FALSE;
	int nError = 0;
	int i = 0;

#if CLSS
	//Pinch Close Check
	for(i = 0; i < 50; i++) //0.5초 동안 검사한다...//
	{
		FAS_GetIoBit(3, FALSE, PINCH_CLOSE1,&bIoResult);
		if(bIoResult == TRUE) 
		{
			break;
		}
		Sleep(10);
	}
	if(i>=49)
	{
		nError = nError+1;
	}

	//CDA OFF CHECK//
	for(i = 0; i < 1000; i++) //10초 동안 검사한다...//
	{
		if(ThreadStage.AdjustInitCode == 'H') //초기 공급 압력
		{
			FAS_GetIoBit(3, FALSE, SUPPLY_INIT_CDA1,&bIoResult11);
			FAS_GetIoBit(3, FALSE, SUPPLY_CDA1,&bIoResult1);

			if((bIoResult1 == FALSE)&&(bIoResult11 == FALSE))
			{
				break;
			}
			Sleep(10);
		}
		else
		{
			FAS_GetIoBit(3, FALSE, SUPPLY_CDA1,&bIoResult1);
			if(bIoResult1 == FALSE)
			{
				break;
			}
			Sleep(10);
		}
	}

	if(i>=999)
	{
		nError = nError+2;
	}

	//NOZZLE 후진 Check//
	for(i = 0; i < 200; i++) //2초 동안 검사한다...//
	{
		FAS_GetIoBit(3, FALSE, NOZZLE_BACKWARD1,&bIoResult2);
		if(bIoResult2 == TRUE) 
		{
			break;
		}
		Sleep(10);
	}

	if(i>=199)
	{
		nError = nError+4;
	}

	return nError;
#else
	for(i = 0; i < 200; i++) //2초 동안 검사한다...//
	{
		FAS_GetIoBit(3, FALSE, NOZZLE_BACKWARD1,&bIoResult2);
		if(bIoResult2 == TRUE) 
		{
			break;
		}
		Sleep(10);
	}
#if _INTERLOCK
	if(i>=199)
	{
		nError = nError+4;
	}
#endif
	return nError;
#endif	
}

