BOOL CP8CA_LcDispView::PairGlassComplete()
{
//	CMainFrame *pFrame = (CMainFrame*)AfxGetMainWnd();
//	CP8CA_LcDispDoc* pDoc = (CP8CA_LcDispDoc*)pFrame->GetActiveDocument();

	short CIM_REPORT_BIT=0x00;
	
	CString str;

	BOOL bComplete = FALSE;
	CString SealCptLotSlot_No_Pair =" ";

	SealCptLotSlot_No_Pair = CIM_Information.LotSlot_No_Pair;
	 //GlsCode로 요구시.."0001"	
	m_pDevice->MNET_WriteWord(GLS_SPC_DATA+0x08, SealCptLotSlot_No_Pair, 1);
	m_pDevice->MNET_WriteWord(GLS_SPC_DATA+0x09, "0001", 1);

	m_pDevice->MNET_BitSet(DISP_REPORT+0x03, true); //Glass Data Req
	Sleep(0);
		
	switch(atoi(m_strMachineNo))
	{
		case 1 : 
//			CIM_REPORT_BIT = 0x00E5; break;
			CIM_REPORT_BIT = 0x00E0; break;
		case 2 :
//			CIM_REPORT_BIT = 0x00E7; break;
			CIM_REPORT_BIT = 0x00E3; break;
	}
			
	g_bTimeOverT3 = FALSE;
	SetTimer(T3_TIMER ,3000, NULL);
	
	while (1) 
	{
		//Ack Code ON?
		if(m_pDevice->MNET_Read_A_Bit(CIM_ACK_BIT,0))
		{
			Sleep(200);
			//Data Report ON?
			if(m_pDevice->MNET_Read_A_Bit(CIM_REPORT_BIT,0))
			{
				m_pDevice->MNET_BitSet(DISP_REPORT+0x03,false); 				
				//Data Read..
				if((ReadPairSpecific() == TRUE) && (ReadValcRun() == TRUE)) //# Read From CIM //Seal에서 완료 했으면...
				{												
					KillTimer(T3_TIMER);
					g_bTimeOverT3 = FALSE;	
					bComplete = TRUE;
					break;
				}
				else 
				{
					KillTimer(T3_TIMER);
					g_bTimeOverT3 = FALSE;	
					bComplete = FALSE;
					break;
				}
			}			
		}
		//Nack Code ON?
		if(m_pDevice->MNET_Read_A_Bit(CIM_ACK_BIT,1))
		{
			m_pDevice->MNET_BitSet(DISP_REPORT+0x03,false); 
			KillTimer(T3_TIMER);
			g_bTimeOverT3 = FALSE;	
			bComplete = FALSE;
			break;
		}
		if(g_bTimeOverT3)
		{
			m_pDevice->MNET_BitSet(DISP_REPORT+0x03,false);
			KillTimer(T3_TIMER);
			g_bTimeOverT3 = FALSE;	
			bComplete = FALSE;
			break;
		}
	}

	if(ReadPairSpecific() == FALSE)	//141013
	{
		ThreadStage.strMsg1="Pair Glass Seal 도포 대기중...";
	}

	else if(ReadValcRun() == FALSE)	//141013
	{
		ThreadStage.strMsg1="Valc Auto 대기중..";
	}

	return bComplete;
}

BOOL CP8CA_LcDispView::ReadPairSpecific()
{
//	CMainFrame *pFrame = (CMainFrame*)AfxGetMainWnd();
//	CP8CA_LcDispDoc *pDoc = (CP8CA_LcDispDoc*)pFrame->GetActiveDocument();

	int temp_value = 0;
	CString str,strLog;
	BOOL bReadCom = FALSE;
	Glass_Specific_Data_Dot_Limit = " ";

	//1호기
	//ReadPairInfo = 0x1910; ReadSelfInfo = 0x1920;
	//2호기
	//ReadPairInfo = 0x1940; ReadSelfInfo = 0x1950; 

	
	//CIM PC 영역은 전호기 동일..
//	ReadPairInfo = 0x00D0; 
//	ReadSelfInfo = 0x00E0;

	short ReadInfoSeal;
	ReadInfoSeal = 0x00E0;
	
	
	//Glass Specific Data 
	//ReadPairInfo???ReadSelfInfo???어떤거로 해야 하지...???
	Glass_Specific_Data_Dot_Limit = m_pDevice->MNET_ReadWord(ReadInfoSeal+0xE, 1, TRUE);

	temp_value = m_pDevice->HexString2Dec(Glass_Specific_Data_Dot_Limit);

	//Seal 1호기 bit 8
	//Seal 2호기 bit 9
	//Seal 1호기 bit A

	if((temp_value>>8 & 0x01) == 0x01)
	{
		bReadCom = TRUE;
	}
	else if((temp_value>>9 & 0x01) == 0x01)
	{
		bReadCom = TRUE;
	}
	else if((temp_value>>10 & 0x01) == 0x01)
	{
		bReadCom = TRUE;
	}
	else
	{
		bReadCom = FALSE;
	}
	return bReadCom;
}


