BOOL CP8CA_LcDispView::FindMark(int nModel)
{
	CMainFrame* pFrame = (CMainFrame*)AfxGetMainWnd();
	CP8CA_LcDispView* pView = (CP8CA_LcDispView*)pFrame->GetActiveView();
	CP8CA_LcDispDoc* pDoc = (CP8CA_LcDispDoc*)pFrame->GetActiveDocument();

	int m_nCameraNo, m_nViewMode, m_nPatternID;
	m_nCameraNo = m_nViewMode = 0;
	m_nPatternID = nModel-1;
	switch(nModel)
	{
	case MUX1:
//		m_nCameraNo = HEAD1_CAM;
		m_nViewMode = MUX1;
		break;
	case MUX2:
//		m_nCameraNo = HEAD1_CAM;
		m_nViewMode = MUX2;
		break;
	}
	
	pView->pVision->Live(m_nViewMode);
	Sleep(500);
	pView->pVision->Grab(m_nViewMode);
	Sleep(300);
	
	CString strtemp;
	if(pView->pVision->FindAlignMark(m_nPatternID, pDoc->m_structDataEditor.m_nCamScore, FALSE))
	{
		if(pView->pVision->m_bFindOK)
		{
			strtemp.Format("Find Align Mark Pattern ID %d", m_nPatternID);
			pView->SaveLog(0,strtemp);
			return TRUE;
		}
		else
		{
			strtemp.Format("Find Align Mark Pattern ID %d RetryCount1 %d RetryCount2 %d Teaching Score %d Curr Score %d", m_nPatternID,pView->pVision->RetryCount1,pView->pVision->RetryCount2,pDoc->m_structDataEditor.m_nCamScore,pView->pVision->m_lScore);
			pView->SaveLog(0,strtemp);
			return TRUE;
		}
	}
	else
	{
		if(pView->pVision->m_bRetryOK == TRUE)
		{
			strtemp.Format("Find Align Mark Pattern ID %d RetryCount1 %d RetryCount2 %d Teaching Score %d Curr Score %d", m_nPatternID,pView->pVision->RetryCount1,pView->pVision->RetryCount2,pDoc->m_structDataEditor.m_nCamScore,pView->pVision->m_lScore);
			pView->SaveLog(0,strtemp);
			return TRUE;
		}
		else
			return FALSE;
	}
}



void CP8CA_LcDispView::SaveBalLog(int BalID, CString strText)
{
	CFileFind filefind;
	FILE *fp;
	CFileException e;
	if(strText == "") return;
	CTime t = CTime::GetCurrentTime();

	// Glass ID Directory 생성
	CString strFileName, strDirName, str;
	BOOL bIsDir = FALSE;
	BOOL bContinue = TRUE;
	CString strFolder/*, = "D:\\BalancelLog3"*/, strTemp;
	// 디렉토리 탐색
	strFolder.Format(g_strLogPath+"\\BalancelLog%d",BalID+1);
	
	filefind.FindFile(g_strLogPath+"\\*.*");
	bIsDir = FALSE;
	bContinue = TRUE;
	while(bContinue)
	{
		bContinue = filefind.FindNextFile();
		if(filefind.IsDirectory())
		{
			strDirName = filefind.GetFileName();
			if(strDirName == strFolder)
			{
				bIsDir = TRUE;
				break;
			}
		}
	}

	filefind.Close();

	if(!bIsDir)	_mkdir(strFolder);
	// 날짜 Directory 생성 완료

	strFileName.Format("%s\\%d-%02d-%02d-Bal%d.log", strFolder,t.GetYear(), t.GetMonth(), t.GetDay(), BalID+1);
	// 화일 열기
	fp = fopen((char *)(LPCSTR)strFileName, "at");
	if(!fp) 
	{
		return;
	}
	str.Format("%02d시%02d분%02d초 - ", t.GetHour(), t.GetMinute(), t.GetSecond());
	str += strText;
	str += "\n";
	fprintf(fp, str);
	fclose(fp);

	// 한달 이전 Log file은 지워버린다...
	// 디렉토리 탐색
	strTemp = strFolder +"\\*.*";
	filefind.FindFile(strTemp);
	bIsDir = FALSE;
	bContinue = TRUE;
	while(bContinue)
	{
		bContinue = filefind.FindNextFile();
		if(!filefind.IsDirectory())
		{
			strFileName = filefind.GetFileName();
			str = strFileName;

			int nYear, nMonth, nDay;
			int nYear1, nMonth1, nDay1;
			nYear = t.GetYear();
			nMonth = t.GetMonth();
			nDay = t.GetDay();

			nYear1 = atoi(str.Mid(0, 4));
			nMonth1 = atoi(str.Mid(5, 2));
			nDay1 = atoi(str.Mid(8, 2));

			if(nYear1 < nYear) 
			{
				::DeleteFile(strFolder +"\\"+strFileName);
			}
			if((nMonth1*30+nDay1) < (nMonth*30+nDay-30))
			{
				::DeleteFile(strFolder +"\\"+strFileName);
			}
		}
	}
}

BOOL CP8CA_LcDispView::AssembleCheck_New(BOOL bCheckOK)
{
	BOOL io_result = false;
	int Head;
	m_nCurrentAssemHead = -1;
	bCheckOK = false;

#include <math.h>
	for(Head=0;Head<MAX_NOZZLE;Head++)
	{
		if(Head < 8)
		{
			FAS_GetIoBit(1,true, ASSEMBLE_SENSOR1+Head, &io_result);
#if EQ
			m_bAssemCheckOK[Head] = io_result;
			 bCheckOK = io_result;
			m_nCurrentAssemHead = Head;
#else
			while(1)
			{
				Head = rand();
				if(Head < 8 && !m_bHeadJointDone[Head])
				{
					break;
				}
			}
			 m_bAssemCheckOK[Head] = TRUE;
			 io_result = m_bAssemCheckOK[Head];
			 bCheckOK = io_result;
			 m_nCurrentAssemHead = Head;
#endif
			return (io_result);	
		}
		else if((Head >= 8) && (Head < MAX_NOZZLE))
		{
			FAS_GetIoBit(1,false, ASSEMBLE_SENSOR9+(Head%8), &io_result);
#if EQ
			m_bAssemCheckOK[Head] = io_result;
			bCheckOK = io_result;
			m_nCurrentAssemHead = Head;
#else
			while(1)
			{
				Head = rand();
				if((Head >= 8) && (Head < MAX_NOZZLE) && !m_bHeadJointDone[Head])
				{
					break;
				}
			}
			 m_bAssemCheckOK[Head] = TRUE;
			 io_result = m_bAssemCheckOK[Head];
			 bCheckOK = io_result;
			 m_nCurrentAssemHead = Head;
#endif
			return (io_result);	
		}
		else
			return FALSE;
	}
}

