void CP8CA_LcDispView::RmsFileBuilt(CString strRecipeNo)
{
	CMainFrame* pFrame = (CMainFrame*)AfxGetMainWnd();
	CP8CA_LcDispDoc* pDoc = (CP8CA_LcDispDoc *)pFrame->GetActiveDocument();

	CString strFront,strNewDir,str_bkR;
	CString strFilePath, strFilePathTo;
	CString strLog;
	int i=0,nR;
//
//	strFront = "001"; // default directory
	strFront = pDoc->m_structOperatorModeRecipeData.strFrontRecipeName;
//For Test
//	structRmsData_Ecs.RecipeNum = "0002";
//
//	i= m_ctrlRecipeList.GetCurSel();
//	strNewDir.Format("%003d",m_nRecipeTemp[i]);
//	str_bkR = structRmsData_Ecs.RecipeNum;
	if(!m_bRecipechangeRoport)
	{
		str_bkR = strRecipeNo;
		nR = m_pDevice->HexConvert(str_bkR.GetAt(1))*256 + m_pDevice->HexConvert(str_bkR.GetAt(2))*16 + m_pDevice->HexConvert(str_bkR.GetAt(3));		
		strNewDir.Format("%003d",nR);
		strLog.Format("<RMS Lv3 Built by Host> Recipe NO %03d",nR);
		SaveRMSLog(strLog);
	}
	else
	{
		strNewDir = strRecipeNo;
		strLog.Format("<RMS Lv3 Built by Disp> Recipe NO %s",strNewDir);
		SaveRMSLog(strLog);
	}
//	if(m_nRecipeTemp[i] <1 || m_nRecipeTemp[i] >100) return;
//	if(m_nRecipeTemp[i] <1 || m_nRecipeTemp[i] >MAX_RECIPE) return;

	if( (nR <1) || (nR >MAX_RECIPE) ) return;
	
	strFilePathTo = _T("d:\\TOP\\P8CA_LC\\P8CA_LC_DATA\\");
	strFilePathTo += strNewDir;
	strFilePathTo += char(0);

	// 메인 디렉 토리가 없으면 폴드를 만든다.
	_mkdir(strFilePathTo);
	strFilePathTo += "\\";
	
 	strFilePath = _T("d:\\TOP\\P8CA_LC\\P8CA_LC_DATA\\");
 	strFilePath += strFront;
 	if(strFilePath.Right(1) != "\\") strFilePath += "\\";
 	strFilePath += "DataEditorMain.dat";
 	strFilePath += char(0);

	// 파일복사를 한다
	SHFILEOPSTRUCT fo;
	fo.hwnd = NULL;
	fo.wFunc = FO_COPY;
	fo.pFrom = (LPCTSTR)strFilePath;
	fo.pTo = (LPCTSTR)strFilePathTo;
	fo.fFlags = FOF_NOCONFIRMMKDIR|FOF_SILENT ;
	fo.fAnyOperationsAborted = TRUE;
	fo.lpszProgressTitle = "파일 복사중";

	::SHFileOperation(&fo);

	strFilePath = _T("d:\\TOP\\P8CA_LC\\P8CA_LC_DATA\\");
	strFilePath += strFront;
	if(strFilePath.Right(1) != "\\") strFilePath += "\\";
	strFilePath += "RMS_Report.dat";
	strFilePath += char(0);


	// 파일복사를 한다
//	SHFILEOPSTRUCT fo;
	fo.hwnd = NULL;
	fo.wFunc = FO_COPY;
	fo.pFrom = (LPCTSTR)strFilePath;
	fo.pTo = (LPCTSTR)strFilePathTo;
	fo.fFlags = FOF_NOCONFIRMMKDIR|FOF_SILENT ;
	fo.fAnyOperationsAborted = TRUE;
	fo.lpszProgressTitle = "파일 복사중";

	::SHFileOperation(&fo);

	// 파일복사 완료 후, Recipe를 다시 부른다
	pDoc->m_arRecipeData.RemoveAll();
//	pDoc->FindRecipeData("d:\\TOP\\P8E_LC\\P8E_LC_DATA\\");
	pDoc->FindRecipeData();
//	SetListData(ORIGIN);

	if(!m_bRecipechangeRoport)
	{
		pDoc->ReadRecipRms(strNewDir);
		pDoc->SaveRmsData(strNewDir);	
	}
}

void CP8CA_LcDispView::RmsFileDelete(CString strRecipeNo)
{
	CMainFrame *pFrame = (CMainFrame *)AfxGetMainWnd();
	CP8CA_LcDispDoc *pDoc = (CP8CA_LcDispDoc *)pFrame->GetActiveDocument();

 //	if(m_ctrlOrigin.GetCurSel () == LB_ERR) return;

	CString str, pname, name, tmp, str_bkR,strNewDir;
	CString dest;
	CString strLog;
	CFileFind find;
	int nR;

//For Test
//	structRmsData_Ecs.RecipeNum = "0002";
//	str_bkR = structRmsData_Ecs.RecipeNum;

	if(!m_bRecipechangeRoport)
	{
		str_bkR = strRecipeNo;
		nR = m_pDevice->HexConvert(str_bkR.GetAt(1))*256 + m_pDevice->HexConvert(str_bkR.GetAt(2))*16 + m_pDevice->HexConvert(str_bkR.GetAt(3));		
		strNewDir.Format("%003d",nR);
		strLog.Format("<RMS Lv3 Del by Host> Recipe NO %03d",nR);
		SaveRMSLog(strLog);
	}
	else
	{
		strNewDir = strRecipeNo;
		str_bkR = strRecipeNo;
		strLog.Format("<RMS Lv3 Del by Disp> Recipe NO %s",str_bkR);
		SaveRMSLog(strLog);
	}

//	str = strPath + "\\*.*";
	str = "d:\\TOP\\P8CA_LC\\P8CA_LC_DATA\\"+strNewDir+"\\*.*";
	
	// 디렉토리가 비어 있을 경우 
	if( find.FindFile( (LPCTSTR)str ) == 0 )
	{
		find.Close();
		// 디렉토리를 삭제
//		if(m_dlgHdOrFd.m_HdOrFd == 1)
//			::RemoveDirectory( (LPCTSTR)srcPath );
		return;
	}
	
	// 화일이 존재 하면 화일을 먼저 지운다. 
	int res = 1;
	BOOL bDel = FALSE;
	while( res )
	{
		res = find.FindNextFile();
		
		name = find.GetFileName();
		pname = find.GetFilePath();

		if( find.IsDirectory() )
		{
			// 가상 디렉토리는 skip
			if( name == "." || name == ".." ) continue;
			// 서브 디렉토리가 존재 하면 재귀 호출 
			//Del(pname);
			RmsFileDelete(str_bkR);
		}
		else
		{
			::DeleteFile( (LPCTSTR)pname );
		}		
	}
	find.Close();

	// 화일의 삭제가 끝나면 디렉토리를 지운다.
//	if(m_dlgHdOrFd.m_HdOrFd == 1)
//	::RemoveDirectory( (LPCTSTR)strPath );
	::RemoveDirectory( (LPCTSTR)("d:\\TOP\\P8CA_LC\\P8CA_LC_DATA\\"+strNewDir));

	// 파일복사 완료 후, Recipe를 다시 부른다
	pDoc->m_arRecipeData.RemoveAll();
//	pDoc->FindRecipeData("d:\\TOP\\P8E_LC\\P8E_LC_DATA\\");
	pDoc->FindRecipeData();	
}

void CP8CA_LcDispView::RmsFileRename(CString strRecipeNo, CString strRecipeNo1)
{
	CMainFrame *pFrame = (CMainFrame *)AfxGetMainWnd();
	CP8CA_LcDispDoc *pDoc = (CP8CA_LcDispDoc *)pFrame->GetActiveDocument();

	CString str_bkR,strNewDir,str_bkR1,strNewDir1;
	CString strLog;
	int nR,nR1;

	if(!m_bRecipechangeRoport)
	{
		str_bkR = strRecipeNo;
		nR = m_pDevice->HexConvert(str_bkR.GetAt(1))*256 + m_pDevice->HexConvert(str_bkR.GetAt(2))*16 + m_pDevice->HexConvert(str_bkR.GetAt(3));		
		strNewDir.Format("%003d",nR);
		strNewDir = "d:\\TOP\\P8CA_LC\\P8CA_LC_DATA\\"+strNewDir;

		strLog.Format("<RMS Lv3 Rename by Host> OLD Recipe NO %03d",nR);
		SaveRMSLog(strLog);
		
		str_bkR1 = strRecipeNo1;
		nR1 = m_pDevice->HexConvert(str_bkR1.GetAt(1))*256 + m_pDevice->HexConvert(str_bkR1.GetAt(2))*16 + m_pDevice->HexConvert(str_bkR1.GetAt(3));		
		strNewDir1.Format("%003d",nR1);
		strNewDir1 = "d:\\TOP\\P8CA_LC\\P8CA_LC_DATA\\"+strNewDir1;

		strLog.Format("<RMS Lv3 Rename by Host> New Recipe NO %03d",nR1);
		SaveRMSLog(strLog);

	}
	else
	{
		strNewDir = strRecipeNo;
		strNewDir = "d:\\TOP\\P8CA_LC\\P8CA_LC_DATA\\"+strNewDir;

		strLog.Format("<RMS Lv3 Rename by Disp> OLD Recipe NO %s",strRecipeNo);
		SaveRMSLog(strLog);

		strNewDir1 = strRecipeNo1;
		strNewDir1 = "d:\\TOP\\P8CA_LC\\P8CA_LC_DATA\\"+strNewDir1;

		strLog.Format("<RMS Lv3 Rename by Disp> New Recipe NO %s",strRecipeNo1);
		SaveRMSLog(strLog);

	}

	rename(strNewDir,strNewDir1);

	// 파일복사 완료 후, Recipe를 다시 부른다
	pDoc->m_arRecipeData.RemoveAll();
//	pDoc->FindRecipeData("d:\\TOP\\P8E_LC\\P8E_LC_DATA\\");
	pDoc->FindRecipeData();
}

void CP8CA_LcDispView::RmsFileChange(CString strRecipeNo)
{
	CMainFrame *pFrame = (CMainFrame *)AfxGetMainWnd();
	CP8CA_LcDispDoc *pDoc = (CP8CA_LcDispDoc *)pFrame->GetActiveDocument();

	CString str_bkR,strNewDir;
	CString strLog;
	int nR;

	if(!m_bRecipechangeRoport)
	{
		str_bkR = strRecipeNo;
		nR = m_pDevice->HexConvert(str_bkR.GetAt(1))*256 + m_pDevice->HexConvert(str_bkR.GetAt(2))*16 + m_pDevice->HexConvert(str_bkR.GetAt(3));		
		strNewDir.Format("%003d",nR);
		strLog.Format("<RMS Lv3 change by Host> Recipe NO %03d",nR);
		SaveRMSLog(strLog);
	}
	else
	{
		strNewDir = strRecipeNo;
		strLog.Format("<RMS Lv3 Rename by Host> OLD Recipe NO %s",strNewDir);
		SaveRMSLog(strLog);
	}

	pDoc->SaveRmsData(strNewDir);	
	pDoc->ReadRecipRms(strNewDir);
}
