void CP8CA_LcDispView::OnVision_Init()		//ehji 140804
{
	_NVision.Engine_End();
	_NVision.Engine_Start();

	if(_NVision.Init_N_Vision()) _NVision.m_structVision_Status.m_bComm_Ok = TRUE;
	else						 _NVision.m_structVision_Status.m_bComm_Ok = FALSE;
}
void CP8CA_LcDispView::AutoButtonSet(BOOL i)	//ehji 140926 Debug 개선.
{
	if(i == FALSE)
	{
		m_ctrlautorun.EnableWindow(false);
		m_ctrlmanual.EnableWindow(false);
		m_ctrlEngMode.EnableWindow(false);
		m_ctrlrecipe.EnableWindow(false);
		m_ctrldataadjust.EnableWindow(false);
		m_ctrldataeditor.EnableWindow(false);
		m_ctrlpass.EnableWindow(false);

	}
	else
	{
		m_ctrlautorun.EnableWindow(true);
		m_ctrlmanual.EnableWindow(true);
		m_ctrlEngMode.EnableWindow(true);
		m_ctrlrecipe.EnableWindow(true);
		m_ctrldataadjust.EnableWindow(true);
		m_ctrldataeditor.EnableWindow(true);
		m_ctrlpass.EnableWindow(true);
	}
}
void CP8CA_LcDispView::OnDblClickLabelModelName(LPDISPATCH Cancel) 
{
	Sleep(100);						//ehji 140926		
	AutoButtonSet(TRUE);			//ehji 140926
}
