void CP8CA_LcDispView::OpenLockDisplay()
{
//////////////////////////////////////////20181130 jeongyong - DoorInterlock정상화
	if(g_DoorLockDispOff == FALSE)
	{
		if(bMaintCheck == TRUE && g_bPvgOn == FALSE) //20181130 jeongyong - DoorInterlock PVG 추가
		{
			bMaintCheck = FALSE;
			m_pDevice->MNET_Mode_Set(1);//IDLE //20211229 JEONGYONG - 안전화면 닫을 때 IDLE 상태 변경
			m_pDevice->MNET_WriteBit(BaseAddr_DISPCTRL+BitDispBuzzer,"0000");
			m_pMaintMode->DestroyWindow();
		}
	}

	else if(g_DoorLockDispOff == TRUE)
	{
		if(bMaintCheck != TRUE)
		{
			bMaintCheck = TRUE;
			m_pDevice->MNET_Mode_Set(3);//DOWN //20211229 JEONGYONG - 안전화면 열 때 DOWN 상태 변경
			m_pDevice->MNET_WriteBit(BaseAddr_DISPCTRL+BitDispBuzzer,"0008");//Buzzer(warning)
			m_pMaintMode = new CMaint;
			m_pMaintMode->Create(IDD_IDLE,this);
			m_pMaintMode->SetWindowPos( NULL, 0, 1, 1024, 780, SWP_SHOWWINDOW | SWP_NOZORDER );
		}
	}
	Sleep(100);
//////////////////////////////////////////20181130 jeongyong - DoorInterlock정상화
}

UINT ThreadBalanceCalibrationCom(UINT BalID, LPVOID pParam)//Balance Calibration 였다 넣는다...
{
	CMainFrame *pFrame = (CMainFrame*)AfxGetMainWnd();

	THREADPARAMS *pThreadParams = (THREADPARAMS *)pParam;
	CP8CA_LcDispView *m_pLcView = pThreadParams->pLcView;
	CP8CA_LcDispDoc *m_pLcDoc = pThreadParams->pLcDoc;
	delete pThreadParams;

	int i=0;
	UINT JobStepBK[MAX_BAL] ={0,};
	BOOL bReSendS = FALSE;
	CString strMsg;

////////////
	for(i=0;i<MAX_BAL;i++)
		ThBal[i].strMsg1.Empty();

	ThBal[BalID].nBalanceMode = 0;//발란스 정상모드여야 함....2010.07.31 by tskim 
	while(!ThBal[BalID].ExitFlag)
	{
		ThBal[BalID].JobStep = JobStepBK[BalID];		
		switch(ThBal[BalID].JobStep)
		{
		case 0: 
			// 초기 cup 무게 측정..
			ThBal[BalID].strMsg1.Format("Bal%d 초기cup무게 측정 중..",BalID+1);
			ThBal[BalID].nBalanceStableCnt = 0;
			ThBal[BalID].bBalanceStableFirstFlag = FALSE;

			m_pLcView->SendData(BalID+1,ThBal[BalID].strBalCmd);		// Sartorius Balance Normal Command

			// SendData하면서,ThBal[BalID]->nTimerCount =0 로한다.
			ThBal[BalID].nTimerCount = 0;
			bReSendS =  true;
			JobStepBK[BalID]++;	
			break;

		case 1:
			// 일정한 시간이 지나도 Data Receive가 되지 않으면, SendData(BAL1,"P")를 다시한다.
			if( (ThBal[BalID].nTimerCount > MAX_TIME) ) 
			{ 
				if(bReSendS == TRUE) { m_pLcView->SendData(BalID+1,ThBal[BalID].strBalCmd); ThBal[BalID].nTimerCount=0 ;bReSendS=FALSE;		}
				else {				   
					ThBal[BalID].strMsg1="Balance 불안정 통신 이상/초기cup무게 측정 실패..";
					strMsg.Format("Step : %d ,%s",JobStepBK[BalID],ThBal[BalID].strMsg1);
					m_pLcView->SaveBalLog(BalID,strMsg); // by ckh 2009.03.13	
					JobStepBK[BalID] = 200;
				}     // ***EXIT***
			}
			else if(ThBal[BalID].bBalanceStableFirstFlag == TRUE)
			{
#if EQ
				ThBal[BalID].dRecentData = ThBal[BalID].dFirstData;
#else
				ThBal[BalID].dRecentData = MAX_CUP_WEIGHT;
#endif
				if(ThBal[BalID].dRecentData > BAL_WEIGHT*1000)	
				{
					ThBal[BalID].strMsg1="발란스내부 측정컵 있음!!";
					strMsg.Format("Step : %d ,%s",JobStepBK[BalID],ThBal[BalID].strMsg1);
					m_pLcView->SendMessage(WM_ERROR,301,BalID);
					m_pLcView->SaveBalLog(BalID,strMsg); // by ckh 2009.03.13
					JobStepBK[BalID]=200;
				}
				else 
				{
					JobStepBK[BalID]++;	
				}
			}
			break;

		case 2:
			// 발란스 교정 실행 
			ThBal[BalID].strMsg1="발란스 교정 실행 중...";
			m_pLcView->SendData(BalID+1,"Z");		// Sartorius Balance Normal Command
			bReSendS =  true;
			JobStepBK[BalID]++;	
			break;

		case 3: 
			ThBal[BalID].strMsg1.Format("Bal%d 교정 중...",BalID+1);
			ThBal[BalID].nBalanceStableCnt = 0;
			ThBal[BalID].bBalanceStableFirstFlag = FALSE;

			m_pLcView->SendData(BalID+1,ThBal[BalID].strBalCmd);		// Sartorius Balance Normal Command

			ThBal[BalID].nBalanceMode = 2; // 교정중이란 상태를 읽기 위해 GetData Mode 구분 

			// SendData하면서,ThBal[BalID]->nTimerCount =0 로한다.
			ThBal[BalID].nTimerCount = 0;
			bReSendS =  true;
			JobStepBK[BalID]++;	
			break;
		case 4 :
			// 일정한 시간이 지나도 Data Receive가 되지 않으면, SendData(BAL1,"P")를 다시한다.
			if(ThBal[BalID].nBalanceMode==2)
			{
				if( (ThBal[BalID].nTimerCount > MAX_TIME/10) ) 
				{ 
				}
				else if(ThBal[BalID].bBalanceStableFirstFlag == TRUE)
				{
#if EQ
//					ThBal[BalID].dRecentData = ThBal[BalID].dFirstData;
#else
					ThBal[BalID].strBalStatus = "C";
#endif
					if(ThBal[BalID].strBalStatus == "C")	//'C' code가 넘어 오지 않으면 교정 작업이 끝나지 않은 거임..여기에 처리..
					{

						ThBal[BalID].strMsg1="발란스 교정 완료 측정 실행 중....";
						strMsg.Format("Step : %d ,%s",JobStepBK[BalID],ThBal[BalID].strMsg1);
						m_pLcView->SaveBalLog(BalID,strMsg); // by ckh 2009.03.13
						ThBal[BalID].nBalanceMode = 0;
					}
					else
					{

					}
				}
			}
			if(ThBal[BalID].nBalanceMode == 0)
			{
				ThBal[BalID].strMsg1.Format("Bal%d 교정 중...",BalID+1);
				ThBal[BalID].nBalanceStableCnt = 0;
				ThBal[BalID].bBalanceStableFirstFlag = FALSE;
				m_pLcView->SendData(BalID+1,ThBal[BalID].strBalCmd);		// Sartorius Balance Normal Command
				// SendData하면서,ThBal[BalID]->nTimerCount =0 로한다.
				ThBal[BalID].nTimerCount = 0;
				bReSendS =  true;
				JobStepBK[BalID]++;	
			}
			break;
		case 5:
			if(ThBal[BalID].nBalanceMode==0)
			{
				if( (ThBal[BalID].nTimerCount > MAX_TIME/10) ) 
				{ 
					m_pLcView->SendData(BalID+1,ThBal[BalID].strBalCmd);
					ThBal[BalID].nTimerCount=0;
					bReSendS=FALSE;		
				}
				//
				else if(ThBal[BalID].bBalanceStableFirstFlag == TRUE)
					JobStepBK[BalID]++;	
			}
//			JobStepBK[BalID]++;			
			break;

		case 6:
			JobStepBK[BalID]++;															
			break;

		case 7:
			JobStepBK[BalID]++;
			break;

		case 8:
			JobStepBK[BalID]++;
			break;
/////////////////////////////////////////////////////////////////////////////////////////////
		// nBalanceStableCnt를 0으로한다.
		case 9 :
			if(ThBal[BalID].nBalanceMode==0)
			{
				ThBal[BalID].strMsg1.Format("Balance%d First 측정 중..",BalID+1);

				ThBal[BalID].nBalanceStableCnt = 0;
				ThBal[BalID].bBalanceStableFirstFlag = FALSE;
				m_pLcView->SendData(BalID+1,ThBal[BalID].strBalCmd);		// Sartorius Balance Normal Command
			}
			else
			{

			}
			ThBal[BalID].nTimerCount = 0;
			bReSendS = true;
			JobStepBK[BalID]++;	
			break;

		// Balance로부터 값이 return될때까지 기다린다. if(m_pLcView->bBalanceStableFirstFlag == TRUE)부분
		// 돌려받은 값을 dFirstData에 저장한다. OnGetData(wParam.lParam)부분.
		case 10 :
			// 일정한 시간이 지나도 Data Receive가 되지 않으면, SendData(BAL3,"P")를 다시한다.
			if(ThBal[BalID].nBalanceMode==0)
			{
				if( (ThBal[BalID].nTimerCount > MAX_TIME) ) 
				{ 
					if(bReSendS == TRUE) { m_pLcView->SendData(BalID+1,ThBal[BalID].strBalCmd);	ThBal[BalID].nTimerCount=0;	bReSendS=FALSE;		}
					else {
						ThBal[BalID].strMsg1.Format("Balance%d 측정 실패..",BalID+1);
						strMsg.Format("Step : %d ,%s",JobStepBK[BalID],ThBal[BalID].strMsg1);
						m_pLcView->SaveBalLog(BalID,strMsg); // by ckh 2009.03.13
						JobStepBK[BalID] = 200;
					} // ***EXIT***			
				}
				//
				else if(ThBal[BalID].bBalanceStableFirstFlag == TRUE)
					JobStepBK[BalID]++;	
			}
			else
			{
				if(ThBal[BalID].bBalanceStableFirstFlag == TRUE)		JobStepBK[BalID]++;	
			}

			break;

		// nBalanceStableCnt를 1로한다.
		case 11 :
			if(ThBal[BalID].nBalanceMode==0)	
			{
				ThBal[BalID].strMsg1.Format("Balance%d Second 측정 중..",BalID+1);
				ThBal[BalID].nBalanceStableCnt = 1;
				ThBal[BalID].bBalanceStableSecondFlag = FALSE ;			
				m_pLcView->SendData(BalID+1,ThBal[BalID].strBalCmd);		// Sartorius Balance Normal Command
			}
			ThBal[BalID].nTimerCount = 0;
			bReSendS = true;
			JobStepBK[BalID]++;
			break;
			// 한번 더 측정..
		case 12 :
#if EQ
#else
			ThBal[BalID].bBalanceStableSecondFlag = TRUE;
#endif
			if(ThBal[BalID].nBalanceMode==0)
			{
				if( (ThBal[BalID].nTimerCount > MAX_TIME/3) ) 
				{ 
					if(bReSendS == TRUE) { m_pLcView->SendData(BalID+1,ThBal[BalID].strBalCmd); ThBal[BalID].nTimerCount=0 ;bReSendS=FALSE;}
					else {
						ThBal[BalID].strMsg1.Format("Balance%d 측정 실패..",BalID+1); 
						strMsg.Format("Step : %d ,%s",JobStepBK[BalID],ThBal[BalID].strMsg1);
						m_pLcView->SaveBalLog(BalID,strMsg); // by ckh 2009.03.13
						JobStepBK[BalID] = 200;
					} // ***EXIT***
				}
				else if(ThBal[BalID].bBalanceStableSecondFlag == TRUE)
					JobStepBK[BalID]++;	
			}
			else	JobStepBK[BalID]++;
			break;

		case 13 :
#if EQ
#else
			ThBal[BalID].nBalanceStableCnt = 2;
#endif
			// dFirstData dSecondData 의 값이 동일하면...
			if(ThBal[BalID].nBalanceStableCnt == 2)
			{
				g_critical.Lock();
				m_pLcView->m_bCalBal_Complete[BalID] = TRUE;
				m_pLcDoc->m_dCommon[0][BalID]=ThBal[BalID].dSecondData;
				JobStepBK[BalID]++;
				g_critical.Unlock();				
			}
			else if(ThBal[BalID].nBalanceStableCnt == 99)
			{
				// dFirstData 와 dSecondData의 값이다르다.
				// 2회정도 반복해도 값이 틀리면, Error를 띄운다.// 아직 안된부분..
				ThBal[BalID].strMsg1.Format("Balance%d First측정값과 Second측정값이 다릅니다. 다시 측정..",BalID+1);
				JobStepBK[BalID] = 12;	
			}
			break;
		case 14 :
			JobStepBK[BalID]++;
			break;

		case 15:
			JobStepBK[BalID]++;
			JobStepBK[BalID] = 200;
			break;

		// EXIT	
		case 200 :
			ThBal[BalID].ExitFlag = true;
			JobStepBK[BalID] = 0;
			ThBal[BalID].nBalanceMode = 0;//발란스 정상모드여야 함....2010.07.31 by tskim 
			break;			
		}// End of switch
		// by ckh 2009.03.19
		if(JobStepBK[BalID] == 200)
		{
			strMsg.Format("%d",ThBal[BalID].JobStep);
			m_pLcView->SaveBalLog(BalID,strMsg);
		}
		//
		Sleep(100);
	}// End of while()
	return 0;
}

void CP8CA_LcDispView::OnClickCmdPendant() 
{
	// TODO: Add your control notification handler code here
	if (AfxMessageBox("Pendant Mode 진입 시 모든 축 Servo off 됩니다. 진행 하시겠습니까?",MB_SYSTEMMODAL|MB_YESNO)==IDYES )//20190711 jeongyong - pendant 추가
	{
		//PM모드 진입 추가
		g_bPendantMode = TRUE;
		ThreadStage.nHomeEnableCount = 0; //원점 초기화
		CPendant dlg; 
		dlg.DoModal();
		g_bPendantMode = FALSE;
	}		
}
